def _resolve_webui_initial_page(pathname: str) -> str | None:
    normalized = pathname.rstrip('/') or '/'
    return _webui_client_route_map.get(normalized)


def _resolve_webui_initial_nav_page(page_id: str | None) -> str | None:
    if page_id is None:
        return None
    if page_id == 'artist-detail':
        return 'library'
    return page_id


def _resolve_webui_initial_react_page(page_id: str | None) -> str | None:
    if page_id in _webui_react_page_ids:
        return page_id
    return None


def _should_serve_webui_spa(pathname: str) -> bool:
    normalized = pathname.rstrip('/') or '/'
    excluded_exact_paths = {'/callback', '/status'}
    excluded_prefixes = (
        '/api',
        '/auth',
        '/callback/',
        '/deezer/',
        '/socket.io',
        '/static',
        '/tidal/',
    )

    if normalized in excluded_exact_paths:
        return False

    return not normalized.startswith(excluded_prefixes)


def _webui_vite_dev_asset_url(asset_path: str) -> str:
    return f'{_webui_vite_url}{_webui_vite_base.rstrip("/")}/{asset_path.lstrip("/")}'


def _load_webui_vite_manifest():
    global _webui_vite_manifest, _webui_vite_manifest_mtime

    manifest_mtime = None
    if _webui_vite_manifest_path.exists():
        try:
            manifest_mtime = _webui_vite_manifest_path.stat().st_mtime
        except OSError:
            manifest_mtime = None

    if _webui_vite_manifest is not None and manifest_mtime == _webui_vite_manifest_mtime:
        return _webui_vite_manifest

    if _webui_vite_manifest_path.exists():
        try:
            with _webui_vite_manifest_path.open('r', encoding='utf-8') as handle:
                _webui_vite_manifest = json.load(handle)
            _webui_vite_manifest_mtime = manifest_mtime
        except Exception as exc:
            logger.warning(f"Failed to load webui manifest: {exc}")
            _webui_vite_manifest = {}
            _webui_vite_manifest_mtime = manifest_mtime
    else:
        _webui_vite_manifest = {}
        _webui_vite_manifest_mtime = None
    return _webui_vite_manifest


def _build_webui_vite_assets(placement='body'):
    if placement not in ('head', 'body'):
        return ''

    if _webui_vite_dev:
        if placement == 'head':
            return ''
        return '\n'.join([
            f'<script type="module" src="{_webui_vite_dev_asset_url("@vite/client")}"></script>',
            f'<script type="module" src="{_webui_vite_dev_asset_url(_webui_vite_entry)}"></script>',
        ])

    manifest = _load_webui_vite_manifest()
    entry = manifest.get(_webui_vite_entry)
    if not entry:
        return ''

    if placement == 'head':
        head_assets = []
        for css_file in entry.get('css', []):
            head_assets.append(f'<link rel="stylesheet" href="{url_for("static", filename=f"dist/{css_file}")}">')
        return '\n'.join(head_assets)

    entry_file = entry.get('file')
    if not entry_file:
        return ''
    return f'<script type="module" src="{url_for("static", filename=f"dist/{entry_file}")}"></script>'


@app.context_processor
def inject_webui_assets():
    return {
        'vite_assets': _build_webui_vite_assets,
    }

# --- Profile Context (before_request hook) ---
@app.before_request
def _set_profile_context():
    """Set g.profile_id from session for every request"""
    g.request_start_monotonic = time.perf_counter()
    # Skip for profile management, static, and root routes
    path = request.path
    if (path.startswith('/api/profiles') or
        path.startswith('/static/') or
        path == '/' or
        path.startswith('/api/v1/')):
        g.profile_id = session.get('profile_id', 1)
        return

    pid = session.get('profile_id', 1)

    # Validate session profile still exists (handles deleted profiles)
    if pid != 1 and 'profile_id' in session:
        try:
            database = get_database()
            profile = database.get_profile(pid)
            if not profile:
                session.pop('profile_id', None)
                from flask import jsonify as _jsonify
                return _jsonify({"error": "profile_required", "message": "Profile no longer exists"}), 401
        except Exception:
            pass  # DB error — don't block requests, use the session value

    g.profile_id = pid


@app.after_request
def _log_slow_request(response):
    """Log slow HTTP requests so we can identify UI stall sources."""
    try:
        path = request.path
        if path.startswith('/socket.io/'):
            return response

        start = getattr(g, 'request_start_monotonic', None)
        if start is None:
            return response

        elapsed_ms = (time.perf_counter() - start) * 1000
        slow_threshold_ms = 1000.0
        if elapsed_ms >= slow_threshold_ms:
            logger.warning(
                "Slow request: %s %s -> %s in %.1fms",
                request.method,
                request.full_path.rstrip('?'),
                response.status_code,
                elapsed_ms,
            )
    except Exception:
        pass

    return response


@app.after_request
def _add_discover_cache_headers(response):
    """Browser-cache discover GETs for 5 minutes.

    The discover surface (hero, similar artists, recent releases, release
    radar, deep cuts, etc.) returns semi-stable data that's expensive to
    compute and not user-action-driven within a session. A short browser
    cache eliminates redundant fetches when the user toggles between
    Discover sections or navigates back.

    Scope: only `/api/discover/` and `/api/discovery/` paths, only GET,
    only successful 2xx responses. Any endpoint that explicitly sets
    its own Cache-Control wins (we don't override).

    Uses `private` not `public` because discover data is user-specific
    (hero artists from your watchlist, similar artists from your taste,
    etc.). `private` keeps it browser-only — intermediate proxies
    (corporate caching proxies, Cloudflare with cache rules, Nginx
    proxy_cache) won't store one user's response and serve it to another.
    """
    try:
        if request.method != 'GET':
            return response
        if not (request.path.startswith('/api/discover/')
                or request.path.startswith('/api/discovery/')):
            return response
        if not (200 <= response.status_code < 300):
            return response
        if response.headers.get('Cache-Control'):
            return response
        response.headers['Cache-Control'] = 'private, max-age=300'
    except Exception as exc:
        # Don't let a header-tagging bug turn a successful response into
        # a 500 — log and ship the response without the cache header.
        logger.warning(f"[discover-cache-headers] failed for {request.path}: {exc}")
    return response


def get_current_profile_id() -> int:
    """Get the current profile ID from Flask g context or default to 1"""
    try:
        return g.profile_id
    except AttributeError:
        return 1


def admin_only(view_fn):
    """Restrict a Flask view to the admin profile (profile_id == 1).

    Settings-class endpoints expose / mutate service tokens, OAuth
    secrets, and API keys. Non-admin profiles must not see them.

    NOTE on the underlying auth model: `get_current_profile_id()`
    defaults to 1 (admin) when no session is present, which means
    single-admin / no-multi-profile installs have no actual gate here —
    any request from the local network is treated as admin. This
    decorator's job is to gate non-admin profiles in MULTI-profile
    setups, not to authenticate the network. The "trust local network"
    posture is the project's existing model; tightening it (real auth
    on every request) is out of scope for this decorator.
    """
    @functools.wraps(view_fn)
    def wrapper(*args, **kwargs):
        if get_current_profile_id() != 1:
            return jsonify({
                "success": False,
                "error": "Admin access required",
            }), 403
        return view_fn(*args, **kwargs)
    return wrapper

# ── Per-profile Spotify client cache ──
_profile_spotify_clients = {}  # profile_id -> SpotifyClient
_profile_spotify_lock = threading.Lock()

def get_spotify_client_for_profile(profile_id=None):
    """Get the Spotify client for the current profile.

    If the profile has custom Spotify credentials, returns a dedicated
    SpotifyClient instance (cached per profile). Otherwise returns the
    global spotify_client.
    """
    if profile_id is None:
        profile_id = get_current_profile_id()

    # Admin (profile 1) always uses global client
    if profile_id == 1:
        return spotify_client

    # Check if this profile has custom Spotify credentials
    try:
        db = get_database()
        creds = db.get_profile_spotify(profile_id)
        if not creds or not creds.get('client_id'):
            return spotify_client  # No custom creds — use global
    except Exception:
        return spotify_client

    # Check cache (don't hold lock during auth check — could block on network)
    with _profile_spotify_lock:
        cached = _profile_spotify_clients.get(profile_id)
    if cached and cached.sp is not None:
        return cached

    # Create a new SpotifyClient for this profile
    try:
        from spotipy.oauth2 import SpotifyOAuth
        import spotipy

        auth_manager = SpotifyOAuth(
            client_id=creds['client_id'],
            client_secret=creds['client_secret'],
            redirect_uri=creds.get('redirect_uri', 'http://127.0.0.1:8888/callback'),
            scope="user-library-read user-read-private playlist-read-private playlist-read-collaborative user-read-email user-follow-read",
            cache_path=f'config/.spotify_cache_profile_{profile_id}'
        )

        # Create a bare SpotifyClient and immediately set the profile-specific
        # spotipy instance (overwrites the global-config one from __init__)
        profile_client = SpotifyClient()
        profile_client.sp = spotipy.Spotify(auth_manager=auth_manager, retries=0, requests_timeout=15)
        profile_client.user_id = None  # Will be fetched lazily

        with _profile_spotify_lock:
            _profile_spotify_clients[profile_id] = profile_client

        logger.info(f"Created per-profile Spotify client for profile {profile_id}")
        return profile_client
    except Exception as e:
        logger.error(f"Failed to create per-profile Spotify client for profile {profile_id}: {e}")
        return spotify_client  # Fall back to global

