def check_download_permission():
    """Check if current profile has download permission. Returns error response or None if allowed."""
    pid = get_current_profile_id()
    if pid == 1:
        return None  # Root admin always allowed
    try:
        profile = get_database().get_profile(pid)
        if profile and not profile.get('can_download', True):
            return jsonify({'success': False, 'error': 'Downloads are disabled for this profile.'}), 403
    except Exception:
        pass  # DB error — don't block
    return None

# --- Docker Helper Functions ---
def docker_resolve_path(path_str):
    """
    Resolve absolute paths for Docker container access
    In Docker, Windows drive paths (E:/) need to be mapped to WSL mount points (/mnt/e/)
    """
    if os.path.exists('/.dockerenv') and len(path_str) >= 3 and path_str[1] == ':' and path_str[0].isalpha():
        # Convert Windows path (E:/path) to WSL mount path (/mnt/e/path)
        drive_letter = path_str[0].lower()
        rest_of_path = path_str[2:].replace('\\', '/')  # Remove E: and convert backslashes
        return f"/host/mnt/{drive_letter}{rest_of_path}"
    return path_str

def extract_filename(full_path):
    """
    Extract filename by working backwards from the end until we hit a separator.
    This is cross-platform compatible and handles both Windows and Unix path separators.

    Special handling for YouTube/Tidal: If the filename contains '||' (encoded format),
    treat it as a filename, not a path, to avoid splitting on '/' in titles.
    """
    if not full_path:
        return ""

    # YouTube filenames are encoded as "video_id||title" and may contain '/' in the title
    # Don't split these on path separators
    if '||' in full_path:
        return full_path

    last_slash = max(full_path.rfind('/'), full_path.rfind('\\'))
    if last_slash != -1:
        return full_path[last_slash + 1:]
    else:
        return full_path

def _make_context_key(username, filename):
    """Build a unique context key from username and full Soulseek path.

    Uses the full remote path (not just filename) to prevent collisions
    when different tracks from the same user share a filename
    (e.g., two albums both containing '01 - Intro.flac').
    """
    normalized = filename.replace('\\', '/').lstrip('/') if filename else ''
    return f"{username}::{normalized}"

