# Tracks cumulative item-processed totals over time for windowed counting.
# Each entry: (timestamp, cumulative_total). Polled every ~5s, 24h = ~17280 entries.

def _get_windowed_calls(key, current_total):
    """Record current cumulative total and return (calls_1h, calls_24h).
    Deque stores (timestamp, cumulative_total) in chronological order.
    To get calls in a window: current_total minus the oldest total within that window."""
    now = time.time()
    history = _enrichment_activity_log.setdefault(key, collections.deque(maxlen=17300))
    history.append((now, current_total))

    cutoff_1h = now - 3600
    cutoff_24h = now - 86400

    # Forward scan: first entry with ts >= cutoff is the oldest in that window
    oldest_1h_total = current_total
    oldest_24h_total = current_total
    found_24h = False
    for ts, total in history:
        if not found_24h and ts >= cutoff_24h:
            oldest_24h_total = total
            found_24h = True
        if ts >= cutoff_1h:
            oldest_1h_total = total
            break

    return max(0, current_total - oldest_1h_total), max(0, current_total - oldest_24h_total)



def _get_enrichment_status():
    """Get lightweight status for all enrichment services (no DB queries).
    Reads worker properties directly to avoid expensive get_stats() calls."""
    services = {}

    # Worker-based enrichment services: (key, display_name, worker_var)
    workers_info = [
        ('musicbrainz', 'MusicBrainz', lambda: mb_worker),
        ('spotify_enrichment', 'Spotify', lambda: spotify_enrichment_worker),
        ('itunes_enrichment', 'iTunes', lambda: itunes_enrichment_worker),
        ('deezer_enrichment', 'Deezer', lambda: deezer_worker),
        ('tidal_enrichment', 'Tidal', lambda: tidal_enrichment_worker),
        ('qobuz_enrichment', 'Qobuz', lambda: qobuz_enrichment_worker),
        ('lastfm', 'Last.fm', lambda: lastfm_worker),
        ('genius', 'Genius', lambda: genius_worker),
        ('audiodb', 'AudioDB', lambda: audiodb_worker),
        ('discogs', 'Discogs', lambda: discogs_worker),
    ]

    # Config-based "configured" checks for services that need API keys/credentials
    configured_checks = {
        'spotify_enrichment': lambda: bool(config_manager.get('spotify.client_id') and config_manager.get('spotify.client_secret')),
        'tidal_enrichment': lambda: bool(tidal_client and getattr(tidal_client, 'access_token', None)),
        'qobuz_enrichment': lambda: bool(qobuz_enrichment_worker and qobuz_enrichment_worker.client and qobuz_enrichment_worker.client.user_auth_token),
        'lastfm': lambda: bool(config_manager.get('lastfm.api_key', '')),
        'genius': lambda: bool(config_manager.get('genius.access_token', '')),
    }

    for key, name, get_worker in workers_info:
        worker = get_worker()
        if worker is not None:
            is_alive = worker.thread is not None and worker.thread.is_alive()
            try:
                configured = configured_checks.get(key, lambda: True)()
            except Exception:
                configured = False

            # Compute windowed API call counts from cumulative stats
            stats = worker.stats
            total_processed = stats.get('matched', 0) + stats.get('not_found', 0) + stats.get('errors', 0)
            calls_1h, calls_24h = _get_windowed_calls(key, total_processed)

            # Debounced idle detection — only report idle after 5s of no current_item
            has_item = getattr(worker, 'current_item', None) is not None
            if has_item:
                _idle_since.pop(key, None)
                is_idle = False
            else:
                if key not in _idle_since:
                    _idle_since[key] = time.time()
                is_idle = (time.time() - _idle_since[key]) >= _IDLE_GRACE_SECONDS

            svc_data = {
                'name': name,
                'configured': configured,
                'running': worker.running and is_alive and not worker.paused,
                'paused': worker.paused,
                'idle': is_alive and not worker.paused and is_idle,
                'calls_1h': calls_1h,
                'calls_24h': calls_24h,
            }

            # Spotify-specific: include daily budget info
            if key == 'spotify_enrichment':
                try:
                    svc_data['daily_budget'] = worker._get_daily_budget_info()
                except Exception:
                    pass

            services[key] = svc_data
        else:
            services[key] = {
                'name': name,
                'configured': False,
                'running': False,
                'paused': False,
                'idle': False,
                'calls_1h': 0,
                'calls_24h': 0,
            }

    # Non-worker services (configured status only)
    services['acoustid'] = {
        'name': 'AcoustID',
        'configured': bool(config_manager.get('acoustid.api_key', '')),
    }
    services['listenbrainz'] = {
        'name': 'ListenBrainz',
        'configured': bool(config_manager.get('listenbrainz.token', '')),
    }

    return services


# Status check caching to reduce unnecessary API calls

@app.route('/status')
def get_status():
    if not config_manager:
        return jsonify({"error": "Server configuration manager is not initialized."}), 500
    try:
        import time

        current_time = time.time()
        active_server = config_manager.get_active_media_server()

        # Test Spotify - with caching to avoid excessive API calls
        if current_time - _status_cache_timestamps['spotify'] > STATUS_CACHE_TTL:
            # Guard against spotify_client being None (partial init)
            is_rate_limited = spotify_client.is_rate_limited() if spotify_client else False
            rate_limit_info = spotify_client.get_rate_limit_info() if (spotify_client and is_rate_limited) else None
            cooldown_remaining = spotify_client.get_post_ban_cooldown_remaining() if spotify_client else 0

            # Read configured source once — no auth validation here, we do that explicitly below
            configured_source = config_manager.get('metadata.fallback_source', 'deezer') or 'deezer'

            if is_rate_limited or cooldown_remaining > 0:
                # During rate limit or post-ban cooldown, skip the auth probe entirely.
                # Probing Spotify here would reset the rate limit timer.
                music_source = 'deezer' if configured_source == 'spotify' else configured_source
                spotify_response_time = 0
            else:
                spotify_start = time.time()
                spotify_connected = spotify_client.is_spotify_authenticated() if spotify_client else False
                spotify_response_time = (time.time() - spotify_start) * 1000
                # Use configured source; fall back to deezer only if Spotify isn't authenticated
                if configured_source == 'spotify':
                    music_source = 'spotify' if spotify_connected else 'deezer'
                else:
                    music_source = configured_source

            _status_cache['spotify'] = {
                'connected': True,  # Always true — iTunes fallback is always available
                'response_time': round(spotify_response_time, 1),
                'source': music_source,
                'rate_limited': is_rate_limited,
                'rate_limit': rate_limit_info,
                'post_ban_cooldown': cooldown_remaining if cooldown_remaining > 0 else None
            }
            _status_cache_timestamps['spotify'] = current_time
        # else: use cached value

        # Test media server - use EXISTING instances (they have internal caching)
        # Media server clients already cache connection checks internally
        if current_time - _status_cache_timestamps['media_server'] > STATUS_CACHE_TTL:
            media_server_start = time.time()
            media_server_status = False
            if active_server == "plex" and plex_client:
                # Use existing instance - has 30s internal connection cache
                media_server_status = plex_client.is_connected()
            elif active_server == "jellyfin" and jellyfin_client:
                # Use existing instance - has internal connection caching
                media_server_status = jellyfin_client.is_connected()
            elif active_server == "navidrome" and navidrome_client:
                # Use existing instance
                media_server_status = navidrome_client.is_connected()
            elif active_server == "soulsync":
                # Standalone mode — always connected if Transfer folder exists
                media_server_status = soulsync_library_client.is_connected() if soulsync_library_client else False
            media_server_response_time = (time.time() - media_server_start) * 1000
            _status_cache['media_server'] = {
                'connected': media_server_status,
                'response_time': round(media_server_response_time, 1),
                'type': active_server
            }
            _status_cache_timestamps['media_server'] = current_time
        # else: use cached value

        # Test Soulseek - only if it's the active source or in the hybrid order
        if current_time - _status_cache_timestamps['soulseek'] > STATUS_CACHE_TTL:
            download_mode = config_manager.get('download_source.mode', 'hybrid')
            hybrid_order = config_manager.get('download_source.hybrid_order', ['hifi', 'youtube', 'soulseek'])
            soulseek_relevant = (download_mode == 'soulseek' or
                                (download_mode == 'hybrid' and 'soulseek' in hybrid_order))

            # Serverless sources (YouTube, HiFi, Qobuz) are always available
            serverless_sources = ('youtube', 'hifi', 'qobuz', 'tidal', 'deezer_dl')
            is_serverless = (download_mode in serverless_sources or
                             (download_mode == 'hybrid' and
                              hybrid_order and any(s in serverless_sources for s in hybrid_order)))

            # Serverless check first — avoids slow slskd timeout when YouTube/HiFi are in hybrid order
            if is_serverless:
                soulseek_status = True
                soulseek_response_time = 0
            elif soulseek_relevant and soulseek_client:
                soulseek_start = time.time()
                try:
                    soulseek_status = run_async(soulseek_client.check_connection())
                except Exception:
                    soulseek_status = False
                soulseek_response_time = (time.time() - soulseek_start) * 1000
            else:
                soulseek_status = False
                soulseek_response_time = 0

            _status_cache['soulseek'] = {
                'connected': soulseek_status,
                'response_time': round(soulseek_response_time, 1)
            }
            _status_cache_timestamps['soulseek'] = current_time

        # Include download source mode so frontend can update labels
        download_mode = config_manager.get('download_source.mode', 'hybrid')
        _status_cache['soulseek']['source'] = download_mode

        # Count active downloads for nav badge
        active_dl_count = 0
        with tasks_lock:
            for t in download_tasks.values():
                if t.get('status') in ('downloading', 'searching', 'post_processing', 'queued', 'pending'):
                    active_dl_count += 1

        status_data = {
            'spotify': _status_cache['spotify'],
            'media_server': _status_cache['media_server'],
            'soulseek': _status_cache['soulseek'],
            'active_media_server': active_server,
            'enrichment': _get_enrichment_status(),
            'active_downloads': active_dl_count,
        }
        return jsonify(status_data)
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/fix-navidrome-urls', methods=['POST'])
def fix_navidrome_urls():
    """Fix Navidrome artist image URLs to use correct Subsonic format"""
    try:
        db = get_database()
        with db._get_connection() as conn:
            cursor = conn.cursor()

            # Get all Navidrome artists with old URL format
            cursor.execute('SELECT id, name, thumb_url FROM artists WHERE server_source = "navidrome" AND thumb_url LIKE "/api/artist/%"')
            artists = cursor.fetchall()

            if not artists:
                return jsonify({"status": "success", "message": "No URLs needed fixing", "updated": 0})

            # Update URLs to new Subsonic format
            import re
            updated = 0
            examples = []

            for artist_id, name, old_url in artists:
                # Extract artist ID from old URL: /api/artist/ARTIST_ID/image
                match = re.search(r'/api/artist/([^/]+)/image', old_url)
                if match:
                    artist_spotify_id = match.group(1)
                    new_url = f'/rest/getCoverArt?id={artist_spotify_id}'

                    cursor.execute('UPDATE artists SET thumb_url = ? WHERE id = ? AND server_source = "navidrome"', (new_url, artist_id))
                    updated += 1

                    if len(examples) < 3:  # Show first 3 as examples
                        examples.append(f'{name}: {old_url} -> {new_url}')

            conn.commit()

            return jsonify({
                "status": "success",
                "message": f"Updated {updated} Navidrome artist URLs to Subsonic format",
                "updated": updated,
                "examples": examples
            })

    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500

def _regenerate_batch_m3u(batch, tracks):
    """Regenerate M3U file for a completed batch using real library DB paths.
    Called from batch completion handler after all post-processing is done."""
    try:
        from difflib import SequenceMatcher
        try:
            from unidecode import unidecode as _unidecode
        except ImportError:
            _unidecode = lambda x: x

        def _norm(text):
            return _unidecode(text).lower().strip() if text else ''

        playlist_name = batch.get('playlist_name', 'Playlist')
        db = get_database()
        active_server = config_manager.get_active_media_server()
        raw_base = config_manager.get('m3u_export.entry_base_path', '') or ''
        entry_base_path = raw_base.rstrip('/\\')

        # Resolve file paths from library DB
        from collections import defaultdict
        artist_groups = defaultdict(list)
        for idx, t in enumerate(tracks):
            artist_groups[t.get('artist', '') or ''].append((idx, t))

        file_path_map = {}
        for artist, group in artist_groups.items():
            if not artist:
                for idx, _ in group:
                    file_path_map[idx] = None
                continue
            db_tracks = db.search_tracks(artist=artist, limit=500, server_source=active_server)
            if not db_tracks:
                for idx, _ in group:
                    file_path_map[idx] = None
                continue
            db_entries = [(_norm(t.title), t) for t in db_tracks]
            for idx, track in group:
                name = track.get('name', '')
                if not name:
                    file_path_map[idx] = None
                    continue
                s_norm = _norm(name)
                matched = None
                for db_n, db_t in db_entries:
                    if s_norm == db_n or SequenceMatcher(None, s_norm, db_n).ratio() >= 0.7:
                        matched = db_t
                        break
                file_path_map[idx] = matched.file_path if matched else None

        # Build M3U content
        import datetime as _dt
        lines = ['#EXTM3U', f'#PLAYLIST:{playlist_name}',
                 f'#GENERATED:{_dt.datetime.utcnow().isoformat()}Z', '']
        found = 0
        for idx, track in enumerate(tracks):
            dur_s = int((track.get('duration_ms', 0) or 0) / 1000)
            artist = track.get('artist', 'Unknown')
            name = track.get('name', 'Unknown')
            lines.append(f'#EXTINF:{dur_s},{artist} - {name}')
            fp = file_path_map.get(idx)
            if fp:
                path = f'{entry_base_path}/{fp}' if entry_base_path else fp
                lines.append(path)
                found += 1
            else:
                lines.append(f'# MISSING: {artist} - {name}')
            lines.append('')

        if found == 0:
            return  # Don't overwrite with an all-missing M3U

        m3u_content = '\n'.join(lines)
        transfer_dir = docker_resolve_path(config_manager.get('soulseek.transfer_path', './Transfer'))
        m3u_folder = _compute_m3u_folder(transfer_dir, 'playlist', playlist_name, '', '', '')
        os.makedirs(m3u_folder, exist_ok=True)
        safe_fn = _sanitize_filename(playlist_name)
        m3u_path = os.path.join(m3u_folder, f'{safe_fn}.m3u')
        with open(m3u_path, 'w', encoding='utf-8') as f:
            f.write(m3u_content)
        logger.info(f"[M3U] Regenerated M3U on batch complete: {m3u_path} ({found}/{len(tracks)} resolved)")
    except Exception as e:
        logger.error(f"[M3U] Error in _regenerate_batch_m3u: {e}")


@app.route('/api/save-playlist-m3u', methods=['POST'])
def save_playlist_m3u():
    """Save M3U playlist file to the relevant download folder"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({"status": "error", "message": "No data provided"}), 400

        playlist_name = data.get('playlist_name', 'Playlist')
        m3u_content = data.get('m3u_content', '')
        context_type = data.get('context_type', 'playlist')
        artist_name = data.get('artist_name', '')
        album_name = data.get('album_name', '')
        year = data.get('year', '')
        force = data.get('force', False)

        # Check if M3U export is enabled (unless force=True from manual Export button)
        if not force and not config_manager.get('m3u_export.enabled', False):
            return jsonify({"status": "success", "message": "M3U export disabled in settings", "skipped": True})

        if not m3u_content:
            return jsonify({"status": "error", "message": "No M3U content provided"}), 400

        # Compute target folder using the template system
        transfer_dir = docker_resolve_path(config_manager.get('soulseek.transfer_path', './Transfer'))
        m3u_folder = _compute_m3u_folder(transfer_dir, context_type, playlist_name, artist_name, album_name, year)
        os.makedirs(m3u_folder, exist_ok=True)

        # Build M3U filename from playlist or album name
        if context_type == 'album' and artist_name and album_name:
            safe_filename = _sanitize_filename(f"{artist_name} - {album_name}")
        else:
            safe_filename = _sanitize_filename(playlist_name)
        m3u_filename = f"{safe_filename}.m3u"
        m3u_path = os.path.join(m3u_folder, m3u_filename)

        # Write M3U file (overwrite if exists)
        with open(m3u_path, 'w', encoding='utf-8') as f:
            f.write(m3u_content)

        logger.info(f"Saved M3U file: {m3u_path}")
        return jsonify({
            "status": "success",
            "message": f"M3U file saved: {m3u_filename}",
            "path": m3u_path
        })

    except Exception as e:
        logger.error(f"Error saving M3U file: {e}")
        return jsonify({"status": "error", "message": str(e)}), 500


@app.route('/api/generate-playlist-m3u', methods=['POST'])
def generate_playlist_m3u():
    """Generate M3U content with real file paths resolved from the library DB.
    Each track entry uses its actual stored file_path rather than a synthesised
    Artist - Title.mp3 string, so media servers can locate the files.
    An optional entry_base_path prefix (from settings) is prepended to every path.
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"success": False, "error": "No data"}), 400

        playlist_name = data.get('playlist_name', 'Playlist')
        tracks = data.get('tracks', [])          # [{name, artist, duration_ms}, ...]
        context_type = data.get('context_type', 'playlist')
        artist_name_ctx = data.get('artist_name', '')
        album_name = data.get('album_name', '')
        year = data.get('year', '')
        save_to_disk = data.get('save_to_disk', False)
        force = data.get('force', False)

        raw_base = config_manager.get('m3u_export.entry_base_path', '') or ''
        entry_base_path = raw_base.rstrip('/\\')

        db = get_database()
        active_server = config_manager.get_active_media_server()

        # --- fuzzy matching helpers (same logic as library_check_tracks) ---
        import re as _re
        from difflib import SequenceMatcher
        try:
            from unidecode import unidecode as _unidecode
        except ImportError:
            _unidecode = lambda x: x

        def _norm(text):
            return _unidecode(text).lower().strip() if text else ''

        def _clean(text):
            s = _norm(text)
            s = _re.sub(r'\s*[\[\(].*?[\]\)]', '', s)
            s = _re.sub(r'\s*-\s*', ' ', s)
            s = _re.sub(r'\s*feat\..*', '', s)
            s = _re.sub(r'\s*featuring.*', '', s)
            s = _re.sub(r'\s*ft\..*', '', s)
            s = _re.sub(r'\s*\d{4}\s*remaster.*', '', s)
            s = _re.sub(r'\s*remaster(ed)?.*', '', s)
            return _re.sub(r'\s+', ' ', s).strip()

        # Group tracks by primary artist to minimise DB queries
        from collections import defaultdict
        artist_groups = defaultdict(list)
        for idx, t in enumerate(tracks):
            artist_groups[t.get('artist', '') or ''].append((idx, t))

        file_path_map = {}
        for artist, group in artist_groups.items():
            if not artist:
                for idx, _ in group:
                    file_path_map[idx] = None
                continue

            db_tracks = db.search_tracks(artist=artist, limit=500, server_source=active_server)
            if not db_tracks:
                for idx, _ in group:
                    file_path_map[idx] = None
                continue

            db_entries = [(_norm(t.title), _clean(t.title), t) for t in db_tracks]

            for idx, track in group:
                name = track.get('name', '')
                if not name:
                    file_path_map[idx] = None
                    continue
                s_norm, s_clean = _norm(name), _clean(name)
                matched = None
                for db_n, db_c, db_t in db_entries:
                    if s_norm == db_n or s_clean == db_c:
                        matched = db_t
                        break
                    if max(SequenceMatcher(None, s_norm, db_n).ratio(),
                           SequenceMatcher(None, s_clean, db_c).ratio()) >= 0.7:
                        matched = db_t
                        break
                file_path_map[idx] = matched.file_path if matched else None

        # --- build M3U content ---
        import datetime as _dt
        found_count = 0
        missing_count = 0
        lines = [
            '#EXTM3U',
            f'#PLAYLIST:{playlist_name}',
            f'#GENERATED:{_dt.datetime.utcnow().isoformat()}Z',
            '',
        ]

        for idx, track in enumerate(tracks):
            name = track.get('name', '') or 'Unknown'
            artist = track.get('artist', '') or 'Unknown Artist'
            dur_s = int((track.get('duration_ms') or 0) / 1000) or -1
            file_path = file_path_map.get(idx)

            lines.append(f'#EXTINF:{dur_s},{artist} - {name}')
            if file_path:
                found_count += 1
                lines.append('#STATUS:FOUND_IN_LIBRARY')
                entry = f'{entry_base_path}/{file_path}' if entry_base_path else file_path
                lines.append(entry.replace('\\', '/'))
            else:
                missing_count += 1
                lines.append('#STATUS:MISSING')
                safe = _re.sub(r'[/\\?%*:|"<>]', '-', f'{artist} - {name}')
                lines.append(f'# NOT AVAILABLE: {safe}')
            lines.append('')

        lines += [
            '#SUMMARY',
            f'#TOTAL_TRACKS:{len(tracks)}',
            f'#FOUND_IN_LIBRARY:{found_count}',
            '#DOWNLOADED:0',
            f'#MISSING:{missing_count}',
        ]
        m3u_content = '\n'.join(lines)

        # --- optionally save to disk ---
        saved_path = None
        if save_to_disk and (force or config_manager.get('m3u_export.enabled', False)):
            transfer_dir = docker_resolve_path(config_manager.get('soulseek.transfer_path', './Transfer'))
            m3u_folder = _compute_m3u_folder(transfer_dir, context_type, playlist_name,
                                              artist_name_ctx, album_name, year)
            os.makedirs(m3u_folder, exist_ok=True)
            if context_type == 'album' and artist_name_ctx and album_name:
                safe_fn = _sanitize_filename(f'{artist_name_ctx} - {album_name}')
            else:
                safe_fn = _sanitize_filename(playlist_name)
            m3u_path = os.path.join(m3u_folder, f'{safe_fn}.m3u')
            with open(m3u_path, 'w', encoding='utf-8') as f:
                f.write(m3u_content)
            saved_path = m3u_path
            logger.info(f"Saved M3U file: {m3u_path}")

        return jsonify({
            "success": True,
            "m3u_content": m3u_content,
            "stats": {"found": found_count, "downloaded": 0, "missing": missing_count},
            "path": saved_path
        })

    except Exception as e:
        logger.error(f"Error generating M3U: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500


def _build_system_stats():
    """Build system statistics dict — shared by HTTP handler and WebSocket emitter."""
    import psutil
    import time
    from datetime import timedelta

    # Calculate uptime
    start_time = getattr(app, 'start_time', time.time())
    uptime_seconds = time.time() - start_time
    uptime = str(timedelta(seconds=int(uptime_seconds)))

    # Get memory usage
    memory = psutil.virtual_memory()
    memory_usage = f"{memory.percent}%"

    # Count active downloads from download_batches (batches that are currently downloading)
    active_downloads = len([batch_id for batch_id, batch_data in download_batches.items()
                           if batch_data.get('phase') == 'downloading'])

    # Count finished downloads (completed this session) - use session counter like dashboard.py
    with session_stats_lock:
        finished_downloads = session_completed_downloads

    # Calculate total download speed from active soulseek transfers
    # Skip the slskd API call entirely when Soulseek is not the active download
    # source — avoids connection timeout spam every 10 seconds for users who have
    # a slskd URL configured but are using YouTube/Tidal/etc.
    total_download_speed = 0.0
    soulseek_known_down = not _status_cache.get('soulseek', {}).get('connected', True)
    download_mode = config_manager.get('download_source.mode', 'hybrid')
    hybrid_order = config_manager.get('download_source.hybrid_order', ['hifi', 'youtube', 'soulseek'])
    soulseek_active = (download_mode == 'soulseek' or
                       (download_mode == 'hybrid' and 'soulseek' in hybrid_order))

    if soulseek_active and not soulseek_known_down:
        try:
            transfers_data = run_async(soulseek_client._make_request('GET', 'transfers/downloads'))
            if transfers_data:
                for user_data in transfers_data:
                    if 'directories' in user_data:
                        for directory in user_data['directories']:
                            if 'files' in directory:
                                for file_info in directory['files']:
                                    state = file_info.get('state', '').lower()
                                    # Only count actively downloading files
                                    if 'inprogress' in state or 'downloading' in state or 'transferring' in state:
                                        speed = file_info.get('averageSpeed', 0)
                                        if isinstance(speed, (int, float)) and speed > 0:
                                            total_download_speed += float(speed)
        except Exception as e:
            logger.error(f"Could not fetch download speeds: {e}")

    # Convert bytes/sec to KB/s and format
    if total_download_speed > 0:
        speed_kb_s = total_download_speed / 1024
        if speed_kb_s >= 1024:
            speed_mb_s = speed_kb_s / 1024
            download_speed_str = f"{speed_mb_s:.1f} MB/s"
        else:
            download_speed_str = f"{speed_kb_s:.1f} KB/s"
    else:
        download_speed_str = "0 KB/s"

    # Count active syncs (playlists currently syncing)
    active_syncs = 0
    # Count Spotify playlist syncs
    for _playlist_id, sync_state in sync_states.items():
        if sync_state.get('status') == 'syncing':
            active_syncs += 1
    # Count YouTube playlist syncs
    for _url_hash, state in youtube_playlist_states.items():
        if state.get('phase') == 'syncing':
            active_syncs += 1
    # Count Tidal playlist syncs
    for _playlist_id, state in tidal_discovery_states.items():
        if state.get('phase') == 'syncing':
            active_syncs += 1

    return {
        'active_downloads': active_downloads,
        'finished_downloads': finished_downloads,
        'download_speed': download_speed_str,
        'active_syncs': active_syncs,
        'uptime': uptime,
        'memory_usage': memory_usage
    }

@app.route('/api/system/stats')
def get_system_stats():
    """Get system statistics for dashboard"""
    try:
        return jsonify(_build_system_stats())
    except Exception as e:
        return jsonify({'error': str(e)}), 500


def _safe_check(fn, default=False):
    """Safely evaluate a check function, returning default on any error."""
    try:
        return fn()
    except Exception:
        return default


@app.route('/api/debug-info')
def get_debug_info():
    """Collect system diagnostics for troubleshooting support requests."""
    import platform
    import sys
    import psutil
    import time
    from datetime import timedelta

    log_lines = request.args.get('lines', 20, type=int)
    log_lines = max(10, min(log_lines, 500))
    log_source = request.args.get('log', 'app')

    info = {}

    # App info
    info['version'] = SOULSYNC_VERSION
    info['os'] = f"{platform.system()} {platform.release()}"
    info['python'] = sys.version.split()[0]
    info['docker'] = os.path.exists('/.dockerenv')
    info['runner'] = 'gunicorn' if not _DIRECT_RUN else 'direct (python web_server.py)'

    # ffmpeg version
    try:
        import subprocess
        result = subprocess.run(['ffmpeg', '-version'], capture_output=True, text=True, timeout=5)
        first_line = result.stdout.split('\n')[0] if result.stdout else ''
        # e.g. "ffmpeg version 6.1.1 Copyright ..."
        info['ffmpeg'] = first_line.split('Copyright')[0].replace('ffmpeg version', '').strip() if first_line else 'installed (version unknown)'
    except FileNotFoundError:
        info['ffmpeg'] = 'NOT INSTALLED'
    except Exception:
        info['ffmpeg'] = 'unknown'

    # Uptime
    start_time = getattr(app, 'start_time', time.time())
    uptime_seconds = time.time() - start_time
    info['uptime'] = str(timedelta(seconds=int(uptime_seconds)))

    # Paths
    download_path = config_manager.get('soulseek.download_path', './downloads')
    transfer_folder = config_manager.get('soulseek.transfer_path', './Transfer')
    staging_folder = config_manager.get('import.staging_path', '')
    info['paths'] = {
        'download_path': download_path,
        'download_path_exists': os.path.isdir(download_path) if download_path else False,
        'download_path_writable': os.access(download_path, os.W_OK) if download_path and os.path.isdir(download_path) else False,
        'transfer_folder': transfer_folder,
        'transfer_folder_exists': os.path.isdir(transfer_folder) if transfer_folder else False,
        'transfer_folder_writable': os.access(transfer_folder, os.W_OK) if transfer_folder and os.path.isdir(transfer_folder) else False,
        'staging_folder': staging_folder,
        'staging_folder_exists': os.path.isdir(staging_folder) if staging_folder else False,
    }
    # Music library paths (Settings > Library)
    music_paths = config_manager.get('library.music_paths', [])
    if isinstance(music_paths, list) and music_paths:
        info['paths']['music_library_paths'] = []
        for p in music_paths:
            if p and isinstance(p, str):
                info['paths']['music_library_paths'].append({
                    'path': p,
                    'exists': os.path.isdir(p),
                })
    # Music videos directory
    music_videos_path = config_manager.get('library.music_videos_path', '')
    if music_videos_path:
        info['paths']['music_videos_path'] = music_videos_path
        info['paths']['music_videos_path_exists'] = os.path.isdir(music_videos_path)

    # Services from status cache
    spotify_cache = _status_cache.get('spotify', {})
    media_server_cache = _status_cache.get('media_server', {})
    soulseek_cache = _status_cache.get('soulseek', {})
    info['services'] = {
        'music_source': spotify_cache.get('source', 'unknown'),
        'spotify_connected': spotify_cache.get('connected', False),
        'spotify_rate_limited': spotify_cache.get('rate_limited', False),
        'media_server_type': media_server_cache.get('type', 'none'),
        'media_server_connected': media_server_cache.get('connected', False),
        'soulseek_connected': soulseek_cache.get('connected', False),
        'download_source': config_manager.get('download_source.mode', 'hybrid'),
        'tidal_connected': _safe_check(lambda: bool(tidal_client and tidal_client.is_authenticated())),
        'qobuz_connected': _safe_check(lambda: bool(qobuz_enrichment_worker and qobuz_enrichment_worker.client and qobuz_enrichment_worker.client.is_authenticated())),
    }

    # Enrichment workers
    workers = {}
    worker_names = ['musicbrainz', 'audiodb', 'deezer', 'spotify', 'itunes', 'lastfm', 'genius', 'discogs', 'tidal', 'qobuz']
    for name in worker_names:
        paused_key = f'{name}_enrichment_paused'
        workers[name] = 'paused' if config_manager.get(paused_key, False) else 'active'
    info['enrichment_workers'] = workers

    # Library stats — use same method as dashboard (filters by active server)
    try:
        db = get_database()
        lib_stats = db.get_database_info_for_server()
        info['library'] = {
            'artists': lib_stats.get('artists', 0),
            'albums': lib_stats.get('albums', 0),
            'tracks': lib_stats.get('tracks', 0),
        }
    except Exception:
        info['library'] = {'artists': 0, 'albums': 0, 'tracks': 0}

    # Watchlist count
    try:
        db = get_database()
        info['watchlist_count'] = db.get_watchlist_count()
    except Exception:
        info['watchlist_count'] = 0

    # Wishlist pending count
    try:
        db = get_database()
        info['wishlist_count'] = db.get_wishlist_count()
    except Exception:
        info['wishlist_count'] = 0

    # Automation count
    try:
        db = get_database()
        automations = db.get_automations()
        info['automations'] = {
            'total': len(automations),
            'enabled': len([a for a in automations if a.get('enabled', False)]),
        }
    except Exception:
        info['automations'] = {'total': 0, 'enabled': 0}

    # Active downloads & syncs (use list() snapshots to avoid RuntimeError from concurrent mutation)
    try:
        active_downloads = len([bid for bid, bd in list(download_batches.items()) if bd.get('phase') == 'downloading'])
    except Exception:
        active_downloads = 0
    active_syncs = 0
    try:
        for _pid, ss in list(sync_states.items()):
            if ss.get('status') == 'syncing':
                active_syncs += 1
        for _uh, st in list(youtube_playlist_states.items()):
            if st.get('phase') == 'syncing':
                active_syncs += 1
        for _pid, st in list(tidal_discovery_states.items()):
            if st.get('phase') == 'syncing':
                active_syncs += 1
    except Exception:
        pass
    info['active_downloads'] = active_downloads
    info['active_syncs'] = active_syncs

    # Config settings relevant to troubleshooting
    source_mode = config_manager.get('download_source.mode', 'hybrid')
    info['config'] = {
        'source_mode': source_mode,
        'quality_profile': config_manager.get('download_source.quality_profile', 'default'),
        'organization_template': config_manager.get('organization.folder_template', ''),
        'post_processing_enabled': config_manager.get('post_processing.enabled', True),
        'acoustid_enabled': bool(config_manager.get('acoustid.api_key', '')),
        'auto_scan_enabled': config_manager.get('watchlist.auto_scan', False),
        'm3u_export_enabled': config_manager.get('m3u.enabled', False),
        'log_level': config_manager.get('logging.level', 'INFO'),
        'primary_metadata_source': config_manager.get('metadata.fallback_source', 'deezer'),
        'lossy_copy_enabled': config_manager.get('post_processing.lossy_copy.enabled', False),
        'lossy_copy_format': config_manager.get('post_processing.lossy_copy.format', 'mp3'),
        'lossy_copy_bitrate': config_manager.get('post_processing.lossy_copy.bitrate', 320),
        'allow_duplicate_tracks': config_manager.get('library.allow_duplicate_tracks', False),
        'replace_lower_quality': config_manager.get('import.replace_lower_quality', False),
        'auto_import_enabled': config_manager.get('import.auto_import_enabled', False),
    }
    # Hybrid source priority order
    if source_mode == 'hybrid':
        info['config']['hybrid_sources'] = config_manager.get('download_source.hybrid_order', [])
    # Discogs connection status
    info['services']['discogs_connected'] = bool(config_manager.get('discogs.token', ''))

    # Download client init failures
    info['download_client_failures'] = []
    if soulseek_client and hasattr(soulseek_client, '_init_failures'):
        info['download_client_failures'] = soulseek_client._init_failures
    elif not soulseek_client:
        info['download_client_failures'] = ['ALL (orchestrator failed to initialize)']

    # API rate monitor — current calls/min, 24h totals, peaks, rate limit events
    try:
        from core.api_call_tracker import api_call_tracker
        rates = api_call_tracker.get_all_rates()
        info['api_rates'] = rates
        # Rich 24h debug summary with peaks, totals, per-endpoint breakdown, events
        info['api_debug_summary'] = api_call_tracker.get_debug_summary()
        # Spotify rate limit details
        if spotify_client:
            rl_info = spotify_client.get_rate_limit_info()
            if rl_info:
                info['spotify_rate_limit'] = {
                    'active': True,
                    'remaining_seconds': rl_info.get('remaining_seconds', 0),
                    'retry_after': rl_info.get('retry_after', 0),
                    'endpoint': rl_info.get('endpoint', ''),
                    'expires_at': rl_info.get('expires_at', ''),
                }
            else:
                info['spotify_rate_limit'] = {'active': False}
    except Exception:
        info['api_rates'] = {}
        info['api_debug_summary'] = {}
        info['spotify_rate_limit'] = {'active': False}

    # Database size
    db_path = os.path.join('database', 'music_library.db')
    if os.path.exists(db_path):
        db_size_mb = os.path.getsize(db_path) / (1024 * 1024)
        info['database_size'] = f"{db_size_mb:.1f} MB"
    else:
        info['database_size'] = 'not found'

    # Memory & CPU
    process = psutil.Process(os.getpid())
    mem = process.memory_info()
    info['memory_usage'] = f"{mem.rss / (1024 * 1024):.0f} MB"
    info['system_memory'] = f"{psutil.virtual_memory().percent}%"
    try:
        info['cpu_percent'] = f"{process.cpu_percent(interval=0.1):.1f}%"
    except Exception:
        info['cpu_percent'] = 'unknown'
    info['thread_count'] = process.num_threads()

    # Log lines
    log_map = {
        'app': Path(_log_path),
        'acoustid': _log_dir / 'acoustid.log',
        'post_processing': _log_dir / 'post_processing.log',
        'source_reuse': _log_dir / 'source_reuse.log',
    }
    log_path = log_map.get(log_source, log_map['app'])
    info['log_source'] = log_source
    info['log_lines_requested'] = log_lines
    info['recent_logs'] = []
    if os.path.exists(log_path):
        try:
            with open(log_path, 'r', encoding='utf-8', errors='replace') as f:
                lines = f.readlines()
                info['recent_logs'] = [line.rstrip() for line in lines[-log_lines:]]
        except Exception:
            info['recent_logs'] = ['(could not read log file)']

    # Available log files
    info['available_logs'] = []
    logs_dir = 'logs'
    if os.path.isdir(logs_dir):
        for fname in sorted(os.listdir(logs_dir)):
            if fname.endswith('.log'):
                fpath = os.path.join(logs_dir, fname)
                size_kb = os.path.getsize(fpath) / 1024
                info['available_logs'].append({
                    'name': fname.replace('.log', ''),
                    'file': fname,
                    'size': f"{size_kb:.0f} KB" if size_kb < 1024 else f"{size_kb/1024:.1f} MB",
                })

    return jsonify(info)


@app.route('/api/activity/feed')
def get_activity_feed():
    """Get recent activity feed for dashboard"""
    try:
        with activity_feed_lock:
            # Return last 10 activities in reverse chronological order
            return jsonify({'activities': activity_feed[-10:][::-1]})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/activity/toasts')
def get_recent_toasts():
    """Get recent activities that should show toasts"""
    try:
        import time
        current_time = time.time()
        
        with activity_feed_lock:
            # Return activities from last 10 seconds that should show toasts
            recent_toasts = [
                activity for activity in activity_feed 
                if activity.get('show_toast', True) and 
                   (current_time - activity.get('timestamp', 0)) <= 10
            ]
            return jsonify({'toasts': recent_toasts})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/logs')
def get_activity_logs():
    """Get formatted activity feed for display in sync page log area"""
    try:
        with activity_feed_lock:
            # Get the last 50 activities (more than the dashboard shows)
            recent_activities = activity_feed[-50:] if len(activity_feed) > 50 else activity_feed[:]

            # Reverse order so newest appears at top
            recent_activities = recent_activities[::-1]

            # Format activities as readable log entries
            formatted_logs = []

            if not recent_activities:
                formatted_logs = [
                    "No recent activity.",
                    "Sync and download operations will appear here in real-time."
                ]
            else:
                for activity in recent_activities:
                    # Format: [TIME] ICON TITLE - SUBTITLE
                    timestamp = activity.get('time', 'Unknown')
                    icon = activity.get('icon', '•')
                    title = activity.get('title', 'Activity')
                    subtitle = activity.get('subtitle', '')

                    # Create a clean, readable log entry
                    if subtitle:
                        log_entry = f"[{timestamp}] {icon} {title} - {subtitle}"
                    else:
                        log_entry = f"[{timestamp}] {icon} {title}"

                    formatted_logs.append(log_entry)

            return jsonify({'logs': formatted_logs})

    except Exception as e:
        return jsonify({'logs': [f'Error reading activity feed: {str(e)}']})

# --- Internal API Key Management (browser-only, no auth) ---
@app.route('/api/v1/api-keys-internal', methods=['GET'])
def list_api_keys_internal():
    """List API keys for the settings page (no auth required — same as all UI routes)."""
    keys = config_manager.get('api_keys', [])
    safe_keys = [
        {
            "id": k.get("id"),
            "label": k.get("label", ""),
            "key_prefix": k.get("key_prefix", ""),
            "created_at": k.get("created_at"),
            "last_used_at": k.get("last_used_at"),
        }
        for k in keys
    ]
    return jsonify({"success": True, "data": {"keys": safe_keys}})

@app.route('/api/v1/api-keys-internal/generate', methods=['POST'])
def generate_api_key_internal():
    """Generate API key from settings page (no auth required)."""
    from api.auth import generate_api_key
    body = request.get_json(silent=True) or {}
    label = body.get("label", "")
    raw_key, record = generate_api_key(label)
    keys = config_manager.get('api_keys', [])
    keys.append(record)
    config_manager.set('api_keys', keys)
    return jsonify({"success": True, "data": {
        "key": raw_key,
        "id": record["id"],
        "label": record["label"],
        "key_prefix": record["key_prefix"],
        "created_at": record["created_at"],
    }}), 201

@app.route('/api/v1/api-keys-internal/revoke/<key_id>', methods=['DELETE'])
def revoke_api_key_internal(key_id):
    """Revoke API key from settings page (no auth required)."""
    keys = config_manager.get('api_keys', [])
    original_len = len(keys)
    keys = [k for k in keys if k.get("id") != key_id]
    if len(keys) == original_len:
        return jsonify({"success": False, "error": {"message": "Key not found"}}), 404
    config_manager.set('api_keys', keys)
    return jsonify({"success": True, "data": {"message": "API key revoked"}})


@app.route('/api/settings', methods=['GET', 'POST'])
@admin_only
def handle_settings():
    global tidal_client # Declare that we might modify the global instance
    if not config_manager:
        return jsonify({"error": "Server configuration manager is not initialized."}), 500
    if request.method == 'POST':
        try:
            new_settings = request.get_json()
            if not new_settings:
                return jsonify({"success": False, "error": "No data received."}), 400

            if 'active_media_server' in new_settings:
                config_manager.set_active_media_server(new_settings['active_media_server'])

            for service in ['spotify', 'plex', 'jellyfin', 'navidrome', 'soulseek', 'download_source', 'settings', 'database', 'metadata_enhancement', 'file_organization', 'playlist_sync', 'tidal', 'tidal_download', 'qobuz', 'hifi_download', 'deezer_download', 'lidarr_download', 'listenbrainz', 'acoustid', 'lastfm', 'genius', 'import', 'lossy_copy', 'listening_stats', 'ui_appearance', 'youtube', 'content_filter', 'itunes', 'm3u_export', 'musicbrainz', 'deezer', 'audiodb', 'metadata', 'hydrabase', 'security', 'discogs', 'library', 'discover', 'wishlist', 'genre_whitelist', 'post_processing']:
                if service in new_settings:
                    for key, value in new_settings[service].items():
                        config_manager.set(f'{service}.{key}', value)

            logger.info("Settings saved successfully via Web UI.")
            
            # Add activity for settings save
            changed_services = list(new_settings.keys())
            services_text = ", ".join(changed_services)
            add_activity_item("", "Settings Updated", f"{services_text} configuration saved", "Now")
            
            add_activity_item("", "Settings Updated", f"{services_text} configuration saved", "Now")
            
            # Reload service clients with new settings (guard against None from partial init)
            if spotify_client:
                spotify_client.reload_config()
            if plex_client:
                plex_client.server = None
            if jellyfin_client:
                jellyfin_client.reload_config()
            if navidrome_client:
                navidrome_client.reload_config()
            # Reload orchestrator settings (download source mode, hybrid_primary, etc.)
            if soulseek_client:
                soulseek_client.reload_settings()
                # Reload YouTube client settings (rate limiting, cookies)
                if hasattr(soulseek_client, 'youtube'):
                    soulseek_client.youtube.reload_settings()
            # FIX: Re-instantiate the global tidal_client to pick up new settings
            try:
                tidal_client = TidalClient()
            except Exception:
                pass  # Keep existing tidal_client if re-init fails
            # Reload enrichment worker clients for key-based services
            if lastfm_worker:
                lastfm_worker._init_client()
            if genius_worker:
                genius_worker._init_client()
            if tidal_enrichment_worker:
                tidal_enrichment_worker.client = tidal_client
            # Invalidate status cache so next poll reflects new settings (e.g. fallback source change)
            _status_cache_timestamps['spotify'] = 0
            logger.info("Service clients re-initialized with new settings.")
            return jsonify({"success": True, "message": "Settings saved successfully."})
        except Exception as e:
            return jsonify({"success": False, "error": str(e)}), 500
    else:  # GET request
        try:
            data = dict(config_manager.config_data)
            # Include which download sources are configured so the UI can auto-disable unconfigured ones
            try:
                data['_source_status'] = soulseek_client.get_source_status()
            except Exception:
                pass
            return jsonify(data)
        except Exception as e:
            return jsonify({"error": str(e)}), 500


