# --- Authentication Routes ---

@app.route('/auth/spotify')
def auth_spotify():
    """
    Initiates Spotify OAuth authentication flow.
    Supports per-profile auth via ?profile_id= query param.
    """
    try:
        profile_id = request.args.get('profile_id', '')

        # Per-profile auth: use profile's own credentials
        if profile_id and profile_id != '1':
            try:
                profile_id_int = int(profile_id)
                db = get_database()
                creds = db.get_profile_spotify(profile_id_int)
                if creds and creds.get('client_id'):
                    from spotipy.oauth2 import SpotifyOAuth
                    redirect_uri = creds.get('redirect_uri') or config_manager.get_spotify_config().get('redirect_uri', 'http://127.0.0.1:8888/callback')
                    auth_manager = SpotifyOAuth(
                        client_id=creds['client_id'],
                        client_secret=creds['client_secret'],
                        redirect_uri=redirect_uri,
                        scope="user-library-read user-read-private playlist-read-private playlist-read-collaborative user-read-email user-follow-read",
                        cache_path=f'config/.spotify_cache_profile_{profile_id_int}',
                        state=f'profile_{profile_id_int}'
                    )
                    auth_url = auth_manager.get_authorize_url()
                    logger.info(f"Per-profile Spotify auth initiated for profile {profile_id_int}")
                    return redirect(auth_url)
            except (ValueError, Exception) as e:
                logger.error(f"Per-profile Spotify auth failed, falling back to global: {e}")

        # Global auth (admin or fallback)
        temp_spotify_client = SpotifyClient()
        if temp_spotify_client.sp and temp_spotify_client.sp.auth_manager:
            # Get the authorization URL
            auth_url = temp_spotify_client.sp.auth_manager.get_authorize_url()
            configured_uri = config_manager.get_spotify_config().get('redirect_uri', 'http://127.0.0.1:8888/callback')
            logger.info(f"Spotify auth initiated — redirect_uri: {configured_uri}")
            add_activity_item("", "Spotify Auth Started", "Please complete OAuth in browser", "Now")

            # Detect if accessing remotely
            host = request.host.split(':')[0]
            is_remote = host not in ['127.0.0.1', 'localhost']
            is_docker = os.path.exists('/.dockerenv')

            # If in Docker and accessing via 127.0.0.1, recommend localhost
            if is_docker and host == '127.0.0.1':
                host = 'localhost'

            # Check if the redirect_uri uses port 8008 (main app) vs the standalone callback server.
            # A localhost URI (127.0.0.1/localhost) on a non-8008 port → standalone callback server.
            # A custom domain or port 8008 → main Flask app (or reverse proxy to it).
            uses_main_port = ':8008' in configured_uri or (
                '127.0.0.1' not in configured_uri and 'localhost' not in configured_uri
            )

            if is_remote or is_docker:
                # Show instructions for remote/docker access
                if uses_main_port:
                    # redirect_uri already points to port 8008 or a custom domain —
                    # callback will come through the main Flask app, no manual steps needed
                    return f'''
                    <html>
                    <head>
                        <style>
                            body {{ font-family: Arial, sans-serif; padding: 20px; max-width: 800px; margin: 0 auto; }}
                            code {{ background: #f0f0f0; padding: 4px 8px; border-radius: 3px; }}
                            .info {{ background: #e3f2fd; border-left: 4px solid #2196F3; padding: 12px 16px; margin: 16px 0; border-radius: 4px; }}
                        </style>
                    </head>
                    <body>
                        <h1>Spotify Authentication</h1>
                        <p>Click the link below to authenticate with Spotify:</p>
                        <p><a href="{auth_url}" target="_blank" style="font-size: 18px; color: #1DB954;">Authenticate with Spotify</a></p>
                        <div class="info">
                            <strong>Redirect URI:</strong> <code>{configured_uri}</code><br>
                            <small>After authorizing, Spotify will redirect back automatically. Make sure this URL matches your Spotify Dashboard redirect URI.</small>
                        </div>
                        <p>After authentication completes, you can close this window and return to SoulSync.</p>
                    </body>
                    </html>
                    '''
                else:
                    # redirect_uri points to the standalone callback server — show manual steps AND suggest switching
                    import re as _re
                    _port_match = _re.search(r':(\d+)/', configured_uri)
                    callback_server_port = _port_match.group(1) if _port_match else str(os.environ.get('SOULSYNC_SPOTIFY_CALLBACK_PORT', '8888'))
                    return f'''
                    <html>
                    <head>
                        <style>
                            body {{ font-family: Arial, sans-serif; padding: 20px; max-width: 800px; margin: 0 auto; }}
                            code {{ background: #f0f0f0; padding: 10px; display: block; margin: 10px 0; }}
                            .highlight {{ background: #e8f5e9; }}
                            .warning {{ background: #fff3e0; border-left: 4px solid #ff9800; padding: 12px 16px; margin: 16px 0; border-radius: 4px; }}
                            .copy-btn {{
                                background: #1DB954;
                                color: white;
                                border: none;
                                padding: 8px 16px;
                                cursor: pointer;
                                border-radius: 4px;
                                font-size: 14px;
                                margin-left: 10px;
                            }}
                            .copy-btn:hover {{ background: #1ed760; }}
                            .copied {{ background: #4CAF50 !important; }}
                        </style>
                    </head>
                    <body>
                        <h1>Spotify Authentication (Remote/Docker)</h1>

                        <div class="warning">
                            <strong>Using a reverse proxy?</strong> Your redirect URI is set to <code style="display:inline; padding: 2px 6px;">{configured_uri}</code>
                            which uses port {callback_server_port}. If you're behind a reverse proxy (Caddy, Nginx, Traefik), change the
                            redirect URI in SoulSync settings to use your proxy URL on the main port instead, e.g.:<br>
                            <code style="display:inline; padding: 2px 6px; background: #e8f5e9;">https://{host}/callback</code><br>
                            Then update the same URI in your <a href="https://developer.spotify.com/dashboard" target="_blank">Spotify Dashboard</a>.
                            This avoids the need for manual URL editing below.
                        </div>

                        <p><strong>Step 1:</strong> Click the link below to authenticate with Spotify</p>
                        <p><a href="{auth_url}" target="_blank" style="font-size: 18px; color: #1DB954;">{auth_url}</a></p>
                        <hr>
                        <p><strong>Step 2:</strong> After authorizing, you'll see a blank page. The URL will look like:</p>
                        <code>http://127.0.0.1:{callback_server_port}/callback?code=...</code>
                        <p><strong>Step 3:</strong> Change <code style="display: inline; background: #ffe6e6; padding: 2px 6px;">127.0.0.1</code> to <code style="display: inline; background: #e8f5e9; padding: 2px 6px;">{host}</code> and press Enter:
                            <button class="copy-btn" onclick="copyIP()">Copy IP</button>
                        </p>
                        <code class="highlight">http://{host}:{callback_server_port}/callback?code=...</code>
                        <p>Authentication will then complete!</p>

                        <script>
                            function copyIP() {{
                                navigator.clipboard.writeText('{host}').then(() => {{
                                    const btn = event.target;
                                    btn.textContent = 'Copied!';
                                    btn.classList.add('copied');
                                    setTimeout(() => {{
                                        btn.textContent = 'Copy IP';
                                        btn.classList.remove('copied');
                                    }}, 2000);
                                }});
                            }}
                        </script>
                    </body>
                    </html>
                    '''
            else:
                # Local access - simple message
                return f'<h1>Spotify Authentication</h1><p>Click the link below to authenticate:</p><p><a href="{auth_url}" target="_blank">{auth_url}</a></p><p>After authentication, return to the app.</p>'
        else:
            return "<h1>Spotify Authentication Failed</h1><p>Could not initialize Spotify client. Check your credentials.</p>", 400
    except Exception as e:
        logger.error(f"Error starting Spotify auth: {e}")
        return f"<h1>Spotify Authentication Error</h1><p>{str(e)}</p>", 500

@app.route('/auth/tidal')
def auth_tidal():
    """
    Initiates Tidal OAuth authentication flow
    """
    logger.info("TIDAL AUTH ROUTE CALLED ")
    try:
        # Create a fresh tidal client to get OAuth URL
        from core.tidal_client import TidalClient
        temp_tidal_client = TidalClient()
        
        if not temp_tidal_client.client_id:
            return "<h1>Tidal Authentication Failed</h1><p>Tidal client ID not configured. Check your credentials.</p>", 400
        
        # Generate PKCE challenge and store globally
        temp_tidal_client._generate_pkce_challenge()
        
        # Store PKCE values globally for callback use
        global tidal_oauth_state
        with tidal_oauth_lock:
            tidal_oauth_state["code_verifier"] = temp_tidal_client.code_verifier
            tidal_oauth_state["code_challenge"] = temp_tidal_client.code_challenge
        
        # Use the user's configured redirect_uri from settings — don't override
        # with request.host, which in Docker returns the container hostname
        configured_redirect = config_manager.get('tidal.redirect_uri', '')
        if configured_redirect:
            temp_tidal_client.redirect_uri = configured_redirect
            logger.info(f"Using configured Tidal redirect_uri: {configured_redirect}")
        else:
            # Fallback: dynamically set based on request host (non-Docker local access)
            request_host = request.host.split(':')[0]
            if request_host not in ('127.0.0.1', 'localhost'):
                dynamic_redirect = f"http://{request_host}:8889/tidal/callback"
                temp_tidal_client.redirect_uri = dynamic_redirect
                logger.info(f"Tidal redirect_uri set from request host: {dynamic_redirect}")

        # Store PKCE + redirect_uri for callback to use the same values
        with tidal_oauth_lock:
            tidal_oauth_state["redirect_uri"] = temp_tidal_client.redirect_uri

        logger.info(f"Stored PKCE - verifier: {temp_tidal_client.code_verifier[:20]}... challenge: {temp_tidal_client.code_challenge[:20]}...")

        # Store profile_id for per-profile auth
        profile_id = request.args.get('profile_id', '')
        with tidal_oauth_lock:
            tidal_oauth_state["profile_id"] = profile_id if profile_id and profile_id != '1' else None

        # Create OAuth URL
        import urllib.parse
        params = {
            'response_type': 'code',
            'client_id': temp_tidal_client.client_id,
            'redirect_uri': temp_tidal_client.redirect_uri,
            'scope': 'user.read playlists.read',
            'code_challenge': temp_tidal_client.code_challenge,
            'code_challenge_method': 'S256'
        }
        
        auth_url = f"{temp_tidal_client.auth_url}?" + urllib.parse.urlencode(params)
        
        logger.info(f"Generated Tidal OAuth URL: {auth_url}")
        logger.info(f"Redirect URI in URL: {params['redirect_uri']}")
        
        add_activity_item("", "Tidal Auth Started", "Please complete OAuth in browser", "Now")

        # Detect if accessing remotely (copied from Spotify auth logic)
        host = request.host.split(':')[0]
        is_remote = host not in ['127.0.0.1', 'localhost']
        is_docker = os.path.exists('/.dockerenv')
        
        # If in Docker and accessing via 127.0.0.1, recommend localhost
        if is_docker and host == '127.0.0.1':
            host = 'localhost'

        if is_remote or is_docker:
            # Show instructions for remote/docker access
            page_title = "Tidal Authentication (Remote/Docker)"
            step_1_text = "Click the link below to authenticate with Tidal"
            
            return f'''
            <html>
            <head>
                <style>
                    body {{ font-family: Arial, sans-serif; padding: 20px; max-width: 800px; margin: 0 auto; }}
                    code {{ background: #f0f0f0; padding: 10px; display: block; margin: 10px 0; }}
                    .highlight {{ background: #e8f5e9; }}
                    .copy-btn {{
                        background: #000000; /* Tidal Black */
                        color: white;
                        border: none;
                        padding: 8px 16px;
                        cursor: pointer;
                        border-radius: 4px;
                        font-size: 14px;
                        margin-left: 10px;
                    }}
                    .copy-btn:hover {{ background: #333333; }}
                    .copied {{ background: #4CAF50 !important; }}
                </style>
            </head>
            <body>
                <h1>{page_title}</h1>
                <p><strong>Step 1:</strong> {step_1_text}</p>
                <p><a href="{auth_url}" target="_blank" style="font-size: 18px; color: #000000;">{auth_url}</a></p>
                <hr>
                <p><strong>Step 2:</strong> After authorizing, you'll see a blank page or an error. The URL will look like:</p>
                <code>http://127.0.0.1:8888/tidal/callback?code=...</code>
                <p><strong>Step 3:</strong> Change <code style="display: inline; background: #ffe6e6; padding: 2px 6px;">127.0.0.1</code> to <code style="display: inline; background: #e8f5e9; padding: 2px 6px;">{host}</code> and press Enter:
                    <button class="copy-btn" onclick="copyIP()">Copy IP</button>
                </p>
                <code class="highlight">http://{host}:8888/tidal/callback?code=...</code>
                <p>Authentication will then complete!</p>

                <script>
                    function copyIP() {{
                        navigator.clipboard.writeText('{host}').then(() => {{
                            const btn = event.target;
                            btn.textContent = 'Copied!';
                            btn.classList.add('copied');
                            setTimeout(() => {{
                                btn.textContent = 'Copy IP';
                                btn.classList.remove('copied');
                            }}, 2000);
                        }});
                    }}
                </script>
            </body>
            </html>
            '''
        else:
            return f'<h1>Tidal Authentication</h1><p>Please visit this URL to authenticate:</p><p><a href="{auth_url}" target="_blank">{auth_url}</a></p><p>After authentication, return to the app.</p>'
        
    except Exception as e:
        logger.error(f"Error starting Tidal auth: {e}")
        import traceback
        logger.error(f"Full traceback: {traceback.format_exc()}")
        return f"<h1>Tidal Authentication Error</h1><p>{str(e)}</p>", 500


@app.route('/callback')
def spotify_callback():
    """
    Handles Spotify OAuth callback via the main Flask app (port 8008).
    This is the recommended callback for reverse proxy / Docker setups.
    The dedicated HTTPServer on port 8888 continues to work for direct/local access.
    """
    global spotify_client
    auth_code = request.args.get('code')

    if not auth_code:
        error = request.args.get('error')
        if error:
            logger.error(f"Spotify OAuth error on port 8008: Spotify returned error: {error}")
            add_activity_item("", "Spotify Auth Failed", f"Spotify returned error: {error}", "Now")
            return f"<h1>Spotify Authentication Failed</h1><p>Spotify returned error: {error}</p>", 400

        # No code AND no error — check if query params were stripped
        if request.args:
            logger.info(f"Spotify callback on port 8008 received unexpected params: {dict(request.args)}")
        else:
            # Completely empty — likely a healthcheck or spurious request
            pass
        return '', 204

    logger.info("Spotify callback received on port 8008 with authorization code")

    # Check for per-profile state parameter
    state = request.args.get('state', '')
    profile_id_from_state = None
    if state and state.startswith('profile_'):
        try:
            profile_id_from_state = int(state.replace('profile_', ''))
            logger.info(f"Per-profile callback detected for profile {profile_id_from_state}")
        except ValueError:
            pass

    try:
        from core.spotify_client import SpotifyClient
        from spotipy.oauth2 import SpotifyOAuth
        from config.settings import config_manager

        # Per-profile callback: use profile's credentials
        if profile_id_from_state and profile_id_from_state != 1:
            db = get_database()
            creds = db.get_profile_spotify(profile_id_from_state)
            if creds and creds.get('client_id'):
                redirect_uri = creds.get('redirect_uri') or config_manager.get_spotify_config().get('redirect_uri', 'http://127.0.0.1:8888/callback')
                auth_manager = SpotifyOAuth(
                    client_id=creds['client_id'],
                    client_secret=creds['client_secret'],
                    redirect_uri=redirect_uri,
                    scope="user-library-read user-read-private playlist-read-private playlist-read-collaborative user-read-email user-follow-read",
                    cache_path=f'config/.spotify_cache_profile_{profile_id_from_state}',
                    state=f'profile_{profile_id_from_state}'
                )
                token_info = auth_manager.get_access_token(auth_code)
                if token_info:
                    # Invalidate cached profile client so it gets recreated with new tokens
                    with _profile_spotify_lock:
                        _profile_spotify_clients.pop(profile_id_from_state, None)
                    add_activity_item("", "Spotify Auth Complete", f"Profile {profile_id_from_state} authenticated with Spotify", "Now")
                    return "<h1>Spotify Authentication Successful!</h1><p>Your personal Spotify account is now connected. You can close this window.</p>"
                else:
                    raise Exception("Failed to exchange authorization code for access token")

        # Global callback (admin)
        config = config_manager.get_spotify_config()
        configured_uri = config.get('redirect_uri', "http://127.0.0.1:8888/callback")
        logger.info(f"Using redirect_uri for token exchange: {configured_uri}")

        auth_manager = SpotifyOAuth(
            client_id=config['client_id'],
            client_secret=config['client_secret'],
            redirect_uri=configured_uri,
            scope="user-library-read user-read-private playlist-read-private playlist-read-collaborative user-read-email user-follow-read",
            cache_path='config/.spotify_cache'
        )

        token_info = auth_manager.get_access_token(auth_code)

        if token_info:
            # CRITICAL: update the GLOBAL spotify_client, not a local variable
            global spotify_client
            spotify_client = SpotifyClient()
            if spotify_client.is_spotify_authenticated():
                # Clear any active rate limit ban and post-ban cooldown
                # so Spotify is immediately usable after re-auth
                from core.spotify_client import _clear_rate_limit
                _clear_rate_limit()
                spotify_client._invalidate_auth_cache()
                # Invalidate status cache so next poll picks up the new connection
                _status_cache_timestamps['spotify'] = 0
                # Refresh enrichment worker's client so it picks up new auth
                if spotify_enrichment_worker and hasattr(spotify_enrichment_worker, 'client'):
                    spotify_enrichment_worker.client.reload_config()
                    spotify_enrichment_worker.client._invalidate_auth_cache()
                add_activity_item("", "Spotify Auth Complete", "Successfully authenticated with Spotify", "Now")
                return "<h1>Spotify Authentication Successful!</h1><p>You can close this window.</p>"
            else:
                raise Exception("Token exchange succeeded but authentication validation failed")
        else:
            raise Exception("Failed to exchange authorization code for access token")
    except Exception as e:
        logger.error(f"Spotify OAuth callback error on port 8008: {e}")
        add_activity_item("", "Spotify Auth Failed", f"Token processing failed: {str(e)}", "Now")
        return f"<h1>Spotify Authentication Failed</h1><p>{str(e)}</p>", 400


@app.route('/api/spotify/disconnect', methods=['POST'])
def spotify_disconnect():
    """Disconnect Spotify and fall back to iTunes/Apple Music"""
    global spotify_client
    try:
        # Pause enrichment worker before disconnecting to prevent it from hammering API
        if spotify_enrichment_worker:
            spotify_enrichment_worker.pause()
        spotify_client.disconnect()
        # Immediately update status cache so UI reflects the change
        fallback_src = _get_metadata_fallback_source()
        _status_cache['spotify'] = {
            'connected': True,  # Fallback source is always available
            'response_time': 0,
            'source': fallback_src,
            'rate_limited': False,
            'rate_limit': None
        }
        _status_cache_timestamps['spotify'] = time.time()
        fallback_label = 'Deezer' if fallback_src == 'deezer' else 'Discogs' if fallback_src == 'discogs' else 'iTunes'
        add_activity_item("", "Spotify Disconnected", f"Switched to {fallback_label} metadata source", "Now")
        return jsonify({'success': True, 'message': f'Spotify disconnected. Now using {fallback_label}.'})
    except Exception as e:
        logger.error(f"Error disconnecting Spotify: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/spotify/rate-limit-status', methods=['GET'])
def spotify_rate_limit_status():
    """Get Spotify rate limit ban details"""
    try:
        info = spotify_client.get_rate_limit_info()
        if info:
            return jsonify({
                'rate_limited': True,
                'remaining_seconds': info['remaining_seconds'],
                'retry_after': info['retry_after'],
                'endpoint': info['endpoint'],
                'expires_at': info['expires_at']
            })
        return jsonify({'rate_limited': False})
    except Exception as e:
        logger.error(f"Error getting Spotify rate limit status: {e}")
        return jsonify({'error': str(e)}), 500


@app.route('/tidal/callback')
def tidal_callback():
    """
    Handles the callback from Tidal after the user authorizes the application.
    It receives an authorization code, exchanges it for an access token,
    and saves the token.
    """
    global tidal_client # We will re-initialize the global client
    auth_code = request.args.get('code')
    
    if not auth_code:
        error = request.args.get('error', 'Unknown error')
        error_description = request.args.get('error_description', 'No description provided.')
        return f"<h1>Tidal Authentication Failed</h1><p>Error: {error}</p><p>{error_description}</p><p>Please close this window and try again.</p>", 400

    try:
        # Create a temporary client for the token exchange
        temp_tidal_client = TidalClient()

        # Restore PKCE values, redirect_uri, and profile_id from the auth request
        profile_id_for_tidal = None
        with tidal_oauth_lock:
            temp_tidal_client.code_verifier = tidal_oauth_state["code_verifier"]
            temp_tidal_client.code_challenge = tidal_oauth_state["code_challenge"]
            if "redirect_uri" in tidal_oauth_state:
                temp_tidal_client.redirect_uri = tidal_oauth_state["redirect_uri"]
            profile_id_for_tidal = tidal_oauth_state.get("profile_id")

        success = temp_tidal_client.fetch_token_from_code(auth_code)

        if success:
            # Per-profile: store tokens on profile, don't touch global client
            if profile_id_for_tidal:
                try:
                    profile_id_int = int(profile_id_for_tidal)
                    db = get_database()
                    # Store Tidal tokens on the profile
                    from config.settings import config_manager as _cm
                    enc_access = _cm._encrypt_value(temp_tidal_client.access_token) if temp_tidal_client.access_token else None
                    enc_refresh = _cm._encrypt_value(temp_tidal_client.refresh_token) if temp_tidal_client.refresh_token else None
                    with db._get_connection() as conn:
                        cursor = conn.cursor()
                        cursor.execute("""
                            UPDATE profiles
                            SET tidal_access_token = ?, tidal_refresh_token = ?,
                                updated_at = CURRENT_TIMESTAMP
                            WHERE id = ?
                        """, (enc_access, enc_refresh, profile_id_int))
                        conn.commit()
                    add_activity_item("", "Tidal Auth Complete", f"Profile {profile_id_int} authenticated with Tidal", "Now")
                    return "<h1>Tidal Authentication Successful!</h1><p>Your personal Tidal account is now connected. You can close this window.</p>"
                except Exception as profile_err:
                    logger.error(f"Per-profile Tidal auth failed, falling back to global: {profile_err}")

            # Global: Re-initialize the main global tidal_client instance with the new token
            tidal_client = TidalClient()
            if tidal_enrichment_worker:
                tidal_enrichment_worker.client = tidal_client
            return "<h1>Tidal Authentication Successful!</h1><p>You can now close this window and return to the SoulSync application.</p>"
        else:
            return "<h1>Tidal Authentication Failed</h1><p>Could not exchange authorization code for a token. Please try again.</p>", 400
    except Exception as e:
        logger.error(f"Error during Tidal token exchange: {e}")
        return f"<h1>An Error Occurred</h1><p>An unexpected error occurred during the authentication process: {e}</p>", 500


