@app.route('/api/library/track/<track_id>/redownload/search-metadata', methods=['POST'])
def redownload_search_metadata(track_id):
    """Search all available metadata sources for a track to find the correct version."""
    try:
        database = get_database()
        conn = database._get_connection()
        cursor = conn.cursor()
        cursor.execute("""
            SELECT t.id, t.title, t.file_path, t.bitrate, t.duration,
                   ar.name AS artist_name, al.title AS album_title,
                   al.thumb_url AS album_thumb_url,
                   t.spotify_track_id, t.deezer_id
            FROM tracks t
            JOIN artists ar ON t.artist_id = ar.id
            JOIN albums al ON t.album_id = al.id
            WHERE t.id = ?
        """, (track_id,))
        row = cursor.fetchone()
        conn.close()

        if not row:
            return jsonify({"success": False, "error": "Track not found"}), 404

        track_title = row['title']
        artist_name = row['artist_name']
        # Clean the title for better search results — strip version/edition suffixes
        import re as _re
        clean_title = _re.sub(r'\s*[\(\[](single version|album version|remaster|deluxe|bonus|explicit|clean|radio edit)[\)\]]', '', track_title, flags=_re.IGNORECASE).strip()
        query = f"{artist_name} {clean_title}"

        # Resolve file info
        file_path = row['file_path'] or ''
        ext = os.path.splitext(file_path)[1].lstrip('.').upper() if file_path else ''
        fmt = ext if ext in ('FLAC', 'MP3', 'OPUS', 'OGG', 'M4A', 'WAV') else ''

        # Resolve album thumb URL (may be relative Plex path)
        thumb_url = row['album_thumb_url'] or ''
        if thumb_url and not thumb_url.startswith('http'):
            _ab = ''
            _at = ''
            if plex_client and plex_client.server:
                _ab = getattr(plex_client.server, '_baseurl', '') or ''
                _at = getattr(plex_client.server, '_token', '') or ''
            if not _ab:
                _pc = config_manager.get_plex_config()
                _ab = (_pc.get('base_url', '') or '').rstrip('/')
                _at = _at or _pc.get('token', '')
            if _ab and thumb_url.startswith('/'):
                thumb_url = f"{_ab}{thumb_url}?X-Plex-Token={_at}" if _at else f"{_ab}{thumb_url}"

        current_track = {
            'id': row['id'],
            'title': track_title,
            'artist': artist_name,
            'album': row['album_title'],
            'duration_ms': row['duration'] or 0,
            'file_path': file_path,
            'format': fmt,
            'bitrate': row['bitrate'] or 0,
            'spotify_track_id': row['spotify_track_id'],
            'deezer_id': row['deezer_id'],
            'thumb_url': thumb_url,
        }

        # Search all available metadata sources in parallel
        from concurrent.futures import ThreadPoolExecutor, as_completed
        from difflib import SequenceMatcher

        def _score_metadata_match(result):
            """Score a metadata result against the current track."""
            title_sim = SequenceMatcher(None, track_title.lower(), (result.get('name') or '').lower()).ratio()
            artist_sim = SequenceMatcher(None, artist_name.lower(), (result.get('artist') or '').lower()).ratio()
            dur_diff = abs((row['duration'] or 0) - (result.get('duration_ms') or 0))
            dur_score = max(0, 1 - dur_diff / 30000) if row['duration'] else 0.5
            return round((title_sim * 0.5 + artist_sim * 0.35 + dur_score * 0.15), 3)

        metadata_results = {}
        sources_to_search = []

        if spotify_client and spotify_client.is_authenticated():
            sources_to_search.append(('spotify', spotify_client))
        try:
            sources_to_search.append(('itunes', _get_itunes_client()))
        except Exception as e:
            logger.debug(f"iTunes client not available for redownload search: {e}")
        try:
            sources_to_search.append(('deezer', _get_deezer_client()))
        except Exception as e:
            logger.debug(f"Deezer client not available for redownload search: {e}")

        # Build source-optimized queries
        deezer_query = f'artist:"{artist_name}" track:"{clean_title}"'

        def _search_source(source_name, client):
            try:
                # Deezer works best with structured artist:/track: queries
                search_q = deezer_query if source_name == 'deezer' else query
                logger.info(f"[Redownload] Searching {source_name} for: {search_q}")
                track_objs = client.search_tracks(search_q, limit=10)
                # If no results, try plain query as fallback
                if not track_objs and search_q != query:
                    track_objs = client.search_tracks(query, limit=10)
                # Last resort: title only
                if not track_objs and clean_title != query:
                    track_objs = client.search_tracks(clean_title, limit=10)
                logger.info(f"[Redownload] {source_name} returned {len(track_objs)} results")
                results = []
                for t in track_objs:
                    r = {
                        'id': str(t.id),
                        'name': t.name,
                        'artist': ', '.join(t.artists) if t.artists else '',
                        'album': t.album or '',
                        'duration_ms': t.duration_ms or 0,
                        'image_url': t.image_url or '',
                        'is_current_match': False,
                    }
                    # Flag current match
                    if source_name == 'spotify' and row['spotify_track_id'] and str(t.id) == str(row['spotify_track_id']):
                        r['is_current_match'] = True
                    elif source_name == 'deezer' and row['deezer_id'] and str(t.id) == str(row['deezer_id']):
                        r['is_current_match'] = True
                    r['match_score'] = _score_metadata_match(r)
                    results.append(r)
                results.sort(key=lambda x: (-int(x['is_current_match']), -x['match_score']))
                return source_name, results
            except Exception as e:
                logger.error(f"[Redownload] Metadata search failed for {source_name}: {e}", exc_info=True)
                return source_name, []

        with ThreadPoolExecutor(max_workers=3) as pool:
            futures = {pool.submit(_search_source, name, client): name for name, client in sources_to_search}
            for future in as_completed(futures):
                source_name, results = future.result()
                metadata_results[source_name] = results

        # Find best overall match
        best_match = None
        for source, results in metadata_results.items():
            if results:
                top = results[0]
                if not best_match or top['match_score'] > best_match['score']:
                    best_match = {'source': source, 'index': 0, 'score': top['match_score']}

        return jsonify({
            "success": True,
            "current_track": current_track,
            "metadata_results": metadata_results,
            "best_match": best_match,
        })
    except Exception as e:
        logger.error(f"Error in redownload metadata search: {e}", exc_info=True)
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/library/track/<track_id>/redownload/search-sources', methods=['POST'])
def redownload_search_sources(track_id):
    """Search all active download sources for a track using the selected metadata."""
    try:
        data = request.get_json()
        metadata = data.get('metadata', {})
        if not metadata.get('name'):
            return jsonify({"success": False, "error": "metadata with name required"}), 400

        # Build a track-like object for query generation
        from core.itunes_client import Track as MetaTrack
        track_obj = MetaTrack(
            id=metadata.get('id', ''),
            name=metadata['name'],
            artists=[metadata.get('artist', '')],
            album=metadata.get('album', ''),
            duration_ms=metadata.get('duration_ms', 0),
            popularity=0,
        )

        # Generate search queries
        search_queries = matching_engine.generate_download_queries(track_obj)
        if not search_queries:
            search_queries = [f"{metadata.get('artist', '')} {metadata['name']}".strip()]

        # Use first 2 queries for speed
        search_queries = search_queries[:2]

        # Search ALL configured download sources individually (not through hybrid which stops at first hit)
        candidates = []
        database = get_database()

        # Get all available download source clients
        download_clients = {}
        try:
            orch = soulseek_client  # The download orchestrator
            if hasattr(orch, 'soulseek') and orch.soulseek:
                if not (hasattr(orch.soulseek, 'is_configured') and not orch.soulseek.is_configured()):
                    download_clients['soulseek'] = orch.soulseek
            if hasattr(orch, 'youtube') and orch.youtube:
                if not (hasattr(orch.youtube, 'is_configured') and not orch.youtube.is_configured()):
                    download_clients['youtube'] = orch.youtube
            if hasattr(orch, 'tidal') and orch.tidal:
                if not (hasattr(orch.tidal, 'is_configured') and not orch.tidal.is_configured()):
                    download_clients['tidal'] = orch.tidal
            if hasattr(orch, 'qobuz') and orch.qobuz:
                if not (hasattr(orch.qobuz, 'is_configured') and not orch.qobuz.is_configured()):
                    download_clients['qobuz'] = orch.qobuz
            if hasattr(orch, 'hifi') and orch.hifi:
                if not (hasattr(orch.hifi, 'is_configured') and not orch.hifi.is_configured()):
                    download_clients['hifi'] = orch.hifi
            if hasattr(orch, 'deezer_dl') and orch.deezer_dl:
                if not (hasattr(orch.deezer_dl, 'is_configured') and not orch.deezer_dl.is_configured()):
                    download_clients['deezer_dl'] = orch.deezer_dl
        except Exception as e:
            logger.warning(f"[Redownload] Error getting download clients: {e}")

        if not download_clients:
            # Fallback: use orchestrator directly
            download_clients = {'default': soulseek_client}

        logger.info(f"[Redownload] Streaming search across {len(download_clients)} sources: {list(download_clients.keys())}")

        def _search_one_source(source_name, client):
            """Search a single download source and return formatted candidates."""
            source_candidates = []
            for _qi, q in enumerate(search_queries):
                try:
                    tracks_result, _ = run_async(client.search(q, timeout=20))
                    if not tracks_result:
                        continue
                    valid = get_valid_candidates(tracks_result, track_obj, q)
                    for candidate in valid:
                        is_bl = database.is_blacklisted(candidate.username, candidate.filename)
                        display_name = os.path.basename(candidate.filename.replace('\\', '/'))
                        ext = os.path.splitext(display_name)[1].lstrip('.').upper()
                        quality = ext if ext in ('FLAC', 'MP3', 'OPUS', 'OGG', 'M4A', 'WAV') else candidate.quality or ''
                        svc = source_name if source_name != 'default' else 'hybrid'
                        uname = candidate.username
                        if uname in ('youtube', 'tidal', 'qobuz', 'hifi', 'deezer_dl', 'lidarr'):
                            svc = uname
                        source_candidates.append({
                            'username': uname,
                            'filename': candidate.filename,
                            'display_name': display_name,
                            'size': candidate.size or 0,
                            'size_display': f"{(candidate.size or 0) / 1048576:.1f} MB",
                            'bitrate': candidate.bitrate or 0,
                            'quality': quality,
                            'duration': candidate.duration or 0,
                            'confidence': round(getattr(candidate, 'confidence', 0), 3),
                            'source_service': svc,
                            'source_query': q,
                            'blacklisted': is_bl,
                            'free_upload_slots': getattr(candidate, 'free_upload_slots', 0),
                            'upload_speed': getattr(candidate, 'upload_speed', 0),
                            'queue_length': getattr(candidate, 'queue_length', 0),
                        })
                except Exception as e:
                    logger.debug(f"[Redownload] {source_name} search failed for query '{q}': {e}")
            # Deduplicate within source
            seen = set()
            unique = []
            for c in source_candidates:
                key = f"{c['username']}|{c['filename']}"
                if key not in seen:
                    seen.add(key)
                    unique.append(c)
            unique.sort(key=lambda c: (-int(not c['blacklisted']), -c['confidence']))
            return unique

        # Stream NDJSON — one line per source as it completes
        from concurrent.futures import ThreadPoolExecutor, as_completed

        def generate_stream():
            with ThreadPoolExecutor(max_workers=4) as pool:
                futures = {pool.submit(_search_one_source, name, client): name for name, client in download_clients.items()}
                for future in as_completed(futures):
                    source_name = futures[future]
                    try:
                        results = future.result()
                        yield json.dumps({'source': source_name, 'candidates': results}) + '\n'
                    except Exception as e:
                        yield json.dumps({'source': source_name, 'candidates': [], 'error': str(e)}) + '\n'
            yield json.dumps({'done': True}) + '\n'

        return app.response_class(generate_stream(), mimetype='application/x-ndjson', headers={'X-Accel-Buffering': 'no'})

    except Exception as e:
        logger.error(f"Error in redownload source search: {e}", exc_info=True)
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/library/track/<track_id>/redownload/start', methods=['POST'])
def redownload_start(track_id):
    """Start downloading a specific track from a selected source to replace the current file."""
    try:
        data = request.get_json()
        metadata = data.get('metadata', {})
        candidate = data.get('candidate', {})
        delete_old = data.get('delete_old_file', True)

        if not candidate.get('username') or not candidate.get('filename'):
            return jsonify({"success": False, "error": "candidate with username and filename required"}), 400

        # Get current track info for old file path
        database = get_database()
        conn = database._get_connection()
        cursor = conn.cursor()
        cursor.execute("SELECT file_path FROM tracks WHERE id = ?", (track_id,))
        row = cursor.fetchone()
        conn.close()

        old_file_path = None
        if row and row['file_path'] and delete_old:
            old_file_path = _resolve_library_file_path(row['file_path'])

        task_id = f"redownload_{track_id}_{int(time.time())}"
        batch_id = f"redownload_batch_{track_id}"

        # Fetch full track details from the metadata source for pipeline parity
        # This gives us track_number, disc_number, full album data
        meta_source = metadata.get('_source', '')
        meta_id = metadata.get('id', '')
        full_track_details = None
        full_album_data = None

        if meta_id:
            try:
                if meta_source == 'spotify' and spotify_client and spotify_client.is_authenticated():
                    full_track_details = spotify_client.get_track_details(meta_id)
                    if full_track_details and full_track_details.get('album', {}).get('id'):
                        full_album_data = spotify_client.get_album(full_track_details['album']['id'])
                elif meta_source == 'itunes':
                    _it = _get_itunes_client()
                    results = _it._lookup(id=meta_id, entity='song')
                    if results:
                        for r in results:
                            if r.get('wrapperType') == 'track':
                                full_track_details = r
                                break
                elif meta_source == 'deezer':
                    _dz = _get_deezer_client()
                    full_track_details = _dz._api_get(f'track/{meta_id}')
            except Exception as e:
                logger.debug(f"[Redownload] Could not fetch full track details: {e}")

        # Build track data with full metadata for pipeline parity
        track_number = None
        disc_number = 1
        album_data = {'name': metadata.get('album', '')}

        if full_track_details:
            if meta_source == 'spotify':
                track_number = full_track_details.get('track_number')
                disc_number = full_track_details.get('disc_number', 1)
                album_raw = full_track_details.get('album', {})
                if album_raw:
                    album_images = album_raw.get('images', [])
                    album_data = {
                        'id': album_raw.get('id', ''),
                        'name': album_raw.get('name', metadata.get('album', '')),
                        'release_date': album_raw.get('release_date', ''),
                        'album_type': album_raw.get('album_type', 'album'),
                        'total_tracks': album_raw.get('total_tracks', 0),
                        'images': album_images,
                        'image_url': album_images[0]['url'] if album_images else '',
                    }
            elif meta_source == 'itunes':
                track_number = full_track_details.get('trackNumber')
                disc_number = full_track_details.get('discNumber', 1)
            elif meta_source == 'deezer':
                track_number = full_track_details.get('track_position')
                disc_number = full_track_details.get('disk_number', 1)

        track_data = {
            'id': meta_id,
            'name': metadata.get('name', ''),
            'artists': [{'name': metadata.get('artist', '')}],
            'album': album_data,
            'duration_ms': metadata.get('duration_ms', 0),
            'track_number': track_number,
            'disc_number': disc_number,
            '_is_explicit_album_download': bool(full_album_data or (album_data.get('id'))),
        }

        # Build explicit context if we have full album data
        if full_album_data or album_data.get('id'):
            track_data['_explicit_album_context'] = full_album_data if isinstance(full_album_data, dict) else album_data
            track_data['_explicit_artist_context'] = {'name': metadata.get('artist', ''), 'id': '', 'genres': []}

        # Create batch
        with tasks_lock:
            download_batches[batch_id] = {
                'queue': [task_id],
                'queue_index': 1,  # Already past the first (only) item
                'active_count': 1,  # One worker is about to start
                'max_concurrent': 1,
                'playlist_id': f'redownload_{track_id}',
                'playlist_name': f"Redownload: {metadata.get('artist', '')} - {metadata.get('name', '')}",
                'phase': 'downloading',
                'total_tracks': 1,
                'completed_count': 0,
                'failed_count': 0,
                'cancelled_tracks': set(),
                'permanently_failed_tracks': [],
                'force_download': True,
                'auto_initiated': False,
            }

            download_tasks[task_id] = {
                'status': 'queued',
                'track_info': track_data,
                'playlist_id': f'redownload_{track_id}',
                'batch_id': batch_id,
                'track_index': 0,
                'download_id': None,
                'username': None,
                'filename': None,
                'retry_count': 0,
                'cached_candidates': [],
                'used_sources': set(),
                'status_change_time': time.time(),
                'metadata_enhanced': False,
                'error_message': None,
                '_redownload_context': {
                    'library_track_id': track_id,
                    'old_file_path': old_file_path,
                    'delete_old_file': delete_old,
                },
            }

        # Build a TrackResult-like candidate and submit to download
        def _run_redownload():
            try:
                from core.soulseek_client import TrackResult
                from core.itunes_client import Track as MetaTrack
                tr = TrackResult(
                    username=candidate['username'],
                    filename=candidate['filename'],
                    size=candidate.get('size', 0),
                    bitrate=candidate.get('bitrate', 0),
                    duration=candidate.get('duration', 0),
                    quality=candidate.get('quality', ''),
                    free_upload_slots=candidate.get('free_upload_slots', 0),
                    upload_speed=candidate.get('upload_speed', 0),
                    queue_length=candidate.get('queue_length', 0),
                )
                tr.artist = metadata.get('artist', '')
                tr.title = metadata.get('name', '')
                tr.album = metadata.get('album', '')
                tr.confidence = candidate.get('confidence', 1.0)

                # Build a proper Track object (not a dict) — _attempt_download_with_candidates
                # accesses track.artists, track.album etc. as attributes
                artist_name = metadata.get('artist', '')
                track_obj = MetaTrack(
                    id=metadata.get('id', ''),
                    name=metadata.get('name', ''),
                    artists=[artist_name] if artist_name else ['Unknown'],
                    album=metadata.get('album', ''),
                    duration_ms=metadata.get('duration_ms', 0),
                    popularity=0,
                )

                _attempt_download_with_candidates(task_id, [tr], track_obj, batch_id)
            except Exception as e:
                logger.error(f"Redownload failed: {e}", exc_info=True)
                with tasks_lock:
                    if task_id in download_tasks:
                        download_tasks[task_id]['status'] = 'failed'
                        download_tasks[task_id]['error_message'] = str(e)

        missing_download_executor.submit(_run_redownload)

        return jsonify({
            "success": True,
            "task_id": task_id,
            "batch_id": batch_id,
            "message": "Redownload started",
        })
    except Exception as e:
        logger.error(f"Error starting redownload: {e}", exc_info=True)
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/library/artist/<artist_id>/sync', methods=['POST'])
def sync_artist_library(artist_id):
    """Bidirectional sync: pull new content from media server AND remove stale entries."""
    try:
        database = get_database()
        with database._get_connection() as conn:
            cursor = conn.cursor()

            # Resolve artist_id: could be a DB integer ID or a source artist ID (Spotify/iTunes/Deezer)
            db_artist_id = None
            # Try direct ID match first (works for both integer and text IDs)
            cursor.execute("SELECT id FROM artists WHERE id = ?", (artist_id,))
            row = cursor.fetchone()
            if row:
                db_artist_id = row['id']
            # Also try as integer (legacy integer PKs)
            if not db_artist_id:
                try:
                    candidate = int(artist_id)
                    cursor.execute("SELECT id FROM artists WHERE id = ?", (candidate,))
                    row = cursor.fetchone()
                    if row:
                        db_artist_id = row['id']
                except (ValueError, TypeError):
                    pass
            # Try source-specific ID columns
            if not db_artist_id:
                for col in ('spotify_artist_id', 'itunes_artist_id', 'deezer_id', 'discogs_id'):
                    cursor.execute(f"SELECT id FROM artists WHERE {col} = ?", (artist_id,))
                    row = cursor.fetchone()
                    if row:
                        db_artist_id = row['id']
                        break

            if not db_artist_id:
                return jsonify({"success": False, "error": "Artist not found"}), 404

            cursor.execute("SELECT name, server_source FROM artists WHERE id = ?", (db_artist_id,))
            artist_row = cursor.fetchone()
            artist_name = artist_row['name'] if artist_row else f'ID {db_artist_id}'
            server_source = artist_row['server_source'] if artist_row else None

        # ── Phase 1: Pull new content from media server ──
        new_albums = 0
        new_tracks = 0
        name_updated = False

        if server_source:
            media_client = None
            if server_source == 'plex' and plex_client and plex_client.server:
                media_client = plex_client
            elif server_source == 'jellyfin' and jellyfin_client:
                media_client = jellyfin_client
            elif server_source == 'navidrome' and navidrome_client:
                media_client = navidrome_client

            if media_client:
                try:
                    from core.database_update_worker import DatabaseUpdateWorker
                    worker = DatabaseUpdateWorker(
                        media_client=media_client,
                        full_refresh=False,
                        server_type=server_source,
                        force_sequential=True,
                    )
                    worker.database = database  # Use existing DB instance instead of creating new one

                    # Fetch the artist object from the server
                    server_artist = None
                    logger.info(f"[Artist Sync] Fetching artist {db_artist_id} from {server_source}...")
                    if server_source == 'plex' and hasattr(media_client, 'server'):
                        try:
                            server_artist = media_client.server.fetchItem(int(db_artist_id))
                            logger.info(f"[Artist Sync] Plex returned: {getattr(server_artist, 'title', 'None')}")
                        except Exception as e:
                            logger.error(f"[Artist Sync] Plex fetchItem failed: {e}")
                    elif hasattr(media_client, 'get_artist_by_id'):
                        try:
                            server_artist = media_client.get_artist_by_id(str(db_artist_id))
                            logger.info(f"[Artist Sync] Server returned: {getattr(server_artist, 'title', None) or server_artist}")
                        except Exception as e:
                            logger.error(f"[Artist Sync] get_artist_by_id failed: {e}")
                    else:
                        logger.warning(f"[Artist Sync] No get_artist_by_id method on {type(media_client).__name__}")

                    if not server_artist:
                        logger.error("[Artist Sync] Could not fetch artist from server — skipping pull phase")

                    if server_artist:
                        # Check for name change
                        new_name = getattr(server_artist, 'title', None)
                        if new_name and new_name != artist_name:
                            database.execute_query(
                                "UPDATE artists SET name = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ?",
                                (new_name, db_artist_id)
                            )
                            logger.info(f"[Artist Sync] Name updated: '{artist_name}' → '{new_name}'")
                            artist_name = new_name
                            name_updated = True

                        # Process artist content (deep scan mode — skip existing, preserve enrichment)
                        success, details, new_albums, new_tracks = worker._process_artist_with_content(
                            server_artist, skip_existing_tracks=True
                        )
                        logger.info(f"[Artist Sync] Server pull for {artist_name}: {details}")

                except Exception as e:
                    logger.error(f"[Artist Sync] Server pull failed for {artist_name}: {e}")

        # ── Phase 2: Remove stale entries (files no longer on disk) ──
        stale_removed = 0
        empty_albums_removed = 0

        with database._get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute("SELECT id, file_path FROM tracks WHERE artist_id = ?", (db_artist_id,))
            tracks = cursor.fetchall()

            stale_ids = []
            for track in tracks:
                fp = track['file_path']
                if not fp:
                    stale_ids.append(track['id'])
                    continue
                resolved = _resolve_library_file_path(fp)
                if not resolved or not os.path.exists(resolved):
                    stale_ids.append(track['id'])

            if stale_ids:
                placeholders = ','.join('?' for _ in stale_ids)
                cursor.execute(f"DELETE FROM tracks WHERE id IN ({placeholders})", stale_ids)
                stale_removed = len(stale_ids)

            cursor.execute("""
                DELETE FROM albums WHERE artist_id = ?
                AND id NOT IN (SELECT DISTINCT album_id FROM tracks)
            """, (db_artist_id,))
            empty_albums_removed = cursor.rowcount

            cursor.execute("""
                UPDATE albums SET track_count = (
                    SELECT COUNT(*) FROM tracks WHERE tracks.album_id = albums.id
                ) WHERE artist_id = ?
            """, (db_artist_id,))

            conn.commit()

        logger.warning(f"[Artist Sync] {artist_name}: +{new_albums} albums, +{new_tracks} tracks, "
              f"-{stale_removed} stale, -{empty_albums_removed} empty albums")

        return jsonify({
            "success": True,
            "artist_name": artist_name,
            "name_updated": name_updated,
            "new_albums": new_albums,
            "new_tracks": new_tracks,
            "stale_removed": stale_removed,
            "empty_albums_removed": empty_albums_removed,
        })

    except Exception as e:
        logger.error(f"Error syncing artist {artist_id}: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500

@app.route('/api/library/album/<album_id>', methods=['DELETE'])
def library_delete_album(album_id):
    """Delete an album and all its tracks from the database, optionally deleting files on disk."""
    try:
        delete_files = request.args.get('delete_files', 'false').lower() == 'true'
        database = get_database()
        files_deleted = 0
        files_failed = 0

        with database._get_connection() as conn:
            cursor = conn.cursor()

            # If deleting files, resolve and remove each track's file first
            if delete_files:
                cursor.execute("SELECT id, file_path FROM tracks WHERE album_id = ?", (album_id,))
                track_rows = cursor.fetchall()
                for row in track_rows:
                    fp = row['file_path']
                    if not fp:
                        continue
                    resolved = _resolve_library_file_path(fp)
                    if resolved and os.path.exists(resolved):
                        try:
                            os.remove(resolved)
                            files_deleted += 1
                            # Clean up sidecar files (.lrc, .txt lyrics)
                            base_no_ext = os.path.splitext(resolved)[0]
                            for sidecar_ext in ('.lrc', '.txt'):
                                sidecar = base_no_ext + sidecar_ext
                                if os.path.exists(sidecar):
                                    try:
                                        os.remove(sidecar)
                                    except Exception:
                                        pass
                        except Exception as e:
                            logger.warning(f"Failed to delete track file: {e}")
                            files_failed += 1
                    else:
                        files_failed += 1

                # Try to remove the album folder if it's now empty
                if track_rows:
                    first_fp = track_rows[0]['file_path']
                    if first_fp:
                        resolved_first = _resolve_library_file_path(first_fp)
                        if resolved_first:
                            album_dir = os.path.dirname(resolved_first)
                            try:
                                if os.path.isdir(album_dir) and not os.listdir(album_dir):
                                    os.rmdir(album_dir)
                                    logger.info(f"Removed empty album directory: {album_dir}")
                            except Exception:
                                pass

            # Delete all tracks belonging to this album
            cursor.execute("DELETE FROM tracks WHERE album_id = ?", (album_id,))
            tracks_deleted = cursor.rowcount
            # Delete the album itself
            cursor.execute("DELETE FROM albums WHERE id = ?", (album_id,))
            if cursor.rowcount == 0:
                conn.rollback()
                return jsonify({"success": False, "error": "Album not found"}), 404
            conn.commit()
            return jsonify({
                "success": True,
                "deleted_count": 1,
                "tracks_deleted": tracks_deleted,
                "files_deleted": files_deleted,
                "files_failed": files_failed
            })
    except Exception as e:
        logger.error(f"Error deleting album {album_id}: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/library/tracks/delete-batch', methods=['POST'])
def library_delete_tracks_batch():
    """Delete multiple track records from the database (does NOT delete files on disk).
    Body: { track_ids: [int] }
    """
    try:
        data = request.get_json()
        track_ids = data.get('track_ids', [])
        if not track_ids or not isinstance(track_ids, list):
            return jsonify({"success": False, "error": "track_ids array is required"}), 400

        database = get_database()
        with database._get_connection() as conn:
            cursor = conn.cursor()
            placeholders = ','.join('?' for _ in track_ids)
            cursor.execute(f"DELETE FROM tracks WHERE id IN ({placeholders})", track_ids)
            conn.commit()
            return jsonify({"success": True, "deleted_count": cursor.rowcount})
    except Exception as e:
        logger.error(f"Error batch deleting tracks: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/library/radio')
def library_radio():
    """Get a smart queue of similar tracks for radio mode auto-play."""
    try:
        track_id = request.args.get('track_id')
        if not track_id:
            return jsonify({"success": False, "error": "track_id is required"}), 400

        limit = request.args.get('limit', 20, type=int)
        exclude_raw = request.args.get('exclude', '')
        exclude_ids = [eid.strip() for eid in exclude_raw.split(',') if eid.strip()] if exclude_raw else None

        database = get_database()
        result = database.get_radio_tracks(track_id, limit=limit, exclude_ids=exclude_ids)

        if not result.get('success'):
            return jsonify(result), 404

        # Fix image URLs (DB stores server-relative paths that need base URL + auth)
        for track in result.get('tracks', []):
            if track.get('image_url'):
                track['image_url'] = fix_artist_image_url(track['image_url'])

        return jsonify(result)
    except Exception as e:
        logger.error(f"Error getting radio tracks: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500


