def _compute_m3u_folder(transfer_dir, context_type, playlist_name, artist_name='', album_name='', year=''):
    """
    Compute the target folder for an M3U file using the template system.

    For playlists: uses playlist_path template, extracts folder portion.
    For albums: uses album_path template, extracts folder portion.

    Returns: absolute folder path
    """
    if context_type == 'album' and artist_name and album_name:
        template_context = {
            'artist': artist_name,
            'albumartist': artist_name,
            'album': album_name,
            'title': 'placeholder',
            'track_number': 1,
            'disc_number': 1,
            'year': year,
            'quality': ''
        }
        folder_path, _ = _get_file_path_from_template(template_context, 'album_path')
        if folder_path:
            return os.path.join(transfer_dir, folder_path)
        # Fallback
        artist_sanitized = _sanitize_filename(artist_name)
        album_sanitized = _sanitize_filename(album_name)
        return os.path.join(transfer_dir, artist_sanitized, f"{artist_sanitized} - {album_sanitized}")
    else:
        template_context = {
            'artist': 'placeholder',
            'albumartist': 'placeholder',
            'album': 'placeholder',
            'title': 'placeholder',
            'playlist_name': playlist_name,
            'track_number': 1,
            'disc_number': 1,
            'year': '',
            'quality': ''
        }
        folder_path, _ = _get_file_path_from_template(template_context, 'playlist_path')
        if folder_path:
            return os.path.join(transfer_dir, folder_path)
        # Fallback
        playlist_sanitized = _sanitize_filename(playlist_name)
        return os.path.join(transfer_dir, playlist_sanitized)


def _get_file_path_from_template_raw(template: str, context: dict) -> tuple:
    """
    Build file path using a user-provided template string directly.
    Unlike _get_file_path_from_template, this bypasses config lookup and the
    file_organization.enabled check — used by the reorganize feature where the
    user supplies the template explicitly.

    Args:
        template: Template string like "$artist/$album/$track - $title"
        context: Dict with all track/album metadata

    Returns:
        (folder_path, filename_base) tuple — no file extension included
    """
    import re
    full_path = _apply_path_template(template, context)

    quality_value = context.get('quality', '')
    disc_value = f"{context.get('disc_number', 1):02d}"
    disc_value_raw = str(context.get('disc_number', 1))

    path_parts = full_path.split('/')

    if len(path_parts) > 1:
        folder_parts = path_parts[:-1]
        filename_base = path_parts[-1]

        # $discnum before $disc — longer match first
        cleaned_folders = []
        for part in folder_parts:
            part = part.replace('$quality', '')
            part = part.replace('$discnum', '')
            part = part.replace('$disc', '')
            part = re.sub(r'\s*\[\s*\]', '', part)
            part = re.sub(r'\s*\(\s*\)', '', part)
            part = re.sub(r'\s*\{\s*\}', '', part)
            part = re.sub(r'\s*-\s*$', '', part)
            part = re.sub(r'^\s*-\s*', '', part)
            part = re.sub(r'\s+', ' ', part).strip()
            if part:
                cleaned_folders.append(part)

        filename_base = filename_base.replace('$quality', quality_value)
        filename_base = filename_base.replace('$discnum', disc_value_raw)
        filename_base = filename_base.replace('$disc', disc_value)
        filename_base = re.sub(r'\s*\[\s*\]', '', filename_base)
        filename_base = re.sub(r'\s*\(\s*\)', '', filename_base)
        filename_base = re.sub(r'\s*\{\s*\}', '', filename_base)
        filename_base = re.sub(r'\s*-\s*$', '', filename_base)
        filename_base = re.sub(r'\s+', ' ', filename_base).strip()

        sanitized_folders = [_sanitize_filename(part) for part in cleaned_folders]
        folder_path = os.path.join(*sanitized_folders) if sanitized_folders else ''
        return folder_path, _sanitize_filename(filename_base)
    else:
        full_path = full_path.replace('$quality', quality_value)
        full_path = full_path.replace('$discnum', disc_value_raw)
        full_path = full_path.replace('$disc', disc_value)
        full_path = re.sub(r'\s*\[\s*\]', '', full_path)
        full_path = re.sub(r'\s*\(\s*\)', '', full_path)
        full_path = re.sub(r'\s*\{\s*\}', '', full_path)
        full_path = re.sub(r'\s*-\s*$', '', full_path)
        full_path = re.sub(r'\s+', ' ', full_path).strip()
        return '', _sanitize_filename(full_path)


def _get_audio_quality_string(file_path):
    """
    Read audio file and return a quality descriptor string.

    Returns strings like 'FLAC 16bit', 'MP3-320', 'M4A-256', 'OGG-192'.
    Returns empty string on any error.
    """
    try:
        ext = os.path.splitext(file_path)[1].lower()

        if ext == '.flac':
            audio = FLAC(file_path)
            bits = audio.info.bits_per_sample
            return f"FLAC {bits}bit"

        elif ext == '.mp3':
            from mutagen.mp3 import MP3, BitrateMode
            audio = MP3(file_path)
            bitrate_kbps = audio.info.bitrate // 1000
            if audio.info.bitrate_mode == BitrateMode.VBR:
                return "MP3-VBR"
            return f"MP3-{bitrate_kbps}"

        elif ext in ('.m4a', '.aac', '.mp4'):
            audio = MP4(file_path)
            bitrate_kbps = audio.info.bitrate // 1000
            return f"M4A-{bitrate_kbps}"

        elif ext == '.ogg':
            audio = OggVorbis(file_path)
            bitrate_kbps = audio.info.bitrate // 1000
            return f"OGG-{bitrate_kbps}"

        elif ext == '.opus':
            from mutagen.oggopus import OggOpus
            audio = OggOpus(file_path)
            bitrate_kbps = audio.info.bitrate // 1000
            return f"OPUS-{bitrate_kbps}"

        return ''
    except Exception as e:
        logger.debug(f"Could not determine audio quality for {file_path}: {e}")
        return ''


def _get_album_type_display(raw_type, track_count) -> str:
    """
    Return the display form of an album's type for the $albumtype template variable.

    Mirrors the inference used in the download pipeline so reorganize output
    matches initial placement. Values: 'Album', 'Single', 'EP', 'Compilation'.
    """
    raw = (raw_type or '').strip().lower()
    try:
        tc = int(track_count or 0)
    except (TypeError, ValueError):
        tc = 0

    # Deezer's raw API returns 'compile' (only mapped to 'compilation' in the
    # Album dataclass path); the Deezer enrichment worker writes the raw value,
    # so both need to match here.
    if raw in ('compilation', 'compile'):
        return 'Compilation'
    if raw == 'album':
        return 'Album'
    if raw in ('single', 'ep'):
        # Match download-pipeline logic: Spotify labels both singles and EPs
        # as 'single', so final classification is by track count. Applying the
        # same rule to explicit 'ep' keeps reorganize consistent with where
        # the files were first placed.
        if tc <= 3:
            return 'Single'
        if tc <= 6:
            return 'EP'
        return 'Album'

    # Unknown/missing — infer from track count
    if tc <= 0:
        return 'Album'
    if tc <= 3:
        return 'Single'
    if tc <= 6:
        return 'EP'
    return 'Album'


def _apply_path_template(template: str, context: dict) -> str:
    """
    Apply template to build file path.

    Args:
        template: Template string like "$artist/$album/$track - $title"
        context: Dict with values like {'artist': 'Drake', 'album': 'Scorpion', ...}

    Returns:
        Processed path string
    """
    # Sanitize context values BEFORE template substitution
    # This prevents '/' in metadata from creating unintended path components
    clean_context = _sanitize_context_values(context)

    result = template

    # Replace variables in order from longest to shortest to avoid partial replacements
    # (e.g., $albumartist must be replaced before $album to prevent "Scorpionartist" from typo "$albumartis")

    # Longest variables first
    album_artist_value = clean_context.get('albumartist', clean_context.get('artist', 'Unknown Artist'))
    # Collaborative album artist handling: "first" uses only the primary artist for folder names
    collab_mode = config_manager.get('file_organization.collab_artist_mode', 'first')
    if collab_mode == 'first' and album_artist_value:
        # Use structured artists list to safely extract first artist
        # Only splits when we have multiple distinct artist objects (Spotify provides these)
        # Avoids string splitting which breaks names like "Tyler, the Creator" or "Simon & Garfunkel"
        artists_list = context.get('_artists_list')
        if artists_list and len(artists_list) > 1:
            # Multiple artist objects (Spotify) — use first
            first = artists_list[0]
            album_artist_value = first.get('name', first) if isinstance(first, dict) else str(first)
        elif artists_list and len(artists_list) == 1:
            # Single artist string — could be a combined name from iTunes
            # Resolve via artistId if available (safe: "Simon & Garfunkel" ID → "Simon & Garfunkel")
            itunes_artist_id = context.get('_itunes_artist_id')
            if itunes_artist_id and (',' in album_artist_value or ' & ' in album_artist_value):
                try:
                    resolved = _get_itunes_client().resolve_primary_artist(itunes_artist_id)
                    if resolved and resolved != album_artist_value:
                        album_artist_value = resolved
                except Exception:
                    pass
    # $cdnum — smart CD label for multi-disc filenames. Produces "CD01" /
    # "CD02" etc. when the album has 2+ discs, empty string otherwise.
    # Empty output collapses gracefully via the trailing double-dash cleanup
    # regex, so single-disc albums don't end up with "CD01" in every name.
    _total_discs = int(clean_context.get('total_discs', 1) or 1)
    _disc_number = int(clean_context.get('disc_number', 1) or 1)
    cdnum_value = f"CD{_disc_number:02d}" if _total_discs > 1 else ''

    # Support ${var} delimited syntax (e.g. ${albumtype}s → Albums)
    # Must run before $var replacements to prevent partial matching
    _bracket_map = {
        'albumartist': album_artist_value,
        'albumtype': clean_context.get('albumtype', 'Album'),
        'playlist': clean_context.get('playlist_name', ''),
        'artistletter': (clean_context.get('artist', 'U') or 'U')[0].upper(),
        'artist': clean_context.get('artist', 'Unknown Artist'),
        'album': clean_context.get('album', 'Unknown Album'),
        'title': clean_context.get('title', 'Unknown Track'),
        'track': f"{clean_context.get('track_number', 1):02d}",
        'cdnum': cdnum_value,
        'disc': str(clean_context.get('disc_number', 1)),
        'discnum': str(clean_context.get('disc_number', 1)),
        'year': str(clean_context.get('year', '')),
        'quality': clean_context.get('quality', ''),
    }
    for var_name, val in _bracket_map.items():
        result = result.replace('${' + var_name + '}', val)

    result = result.replace('$albumartist', album_artist_value)
    result = result.replace('$albumtype', clean_context.get('albumtype', 'Album'))
    result = result.replace('$playlist', clean_context.get('playlist_name', ''))

    # Medium length variables
    result = result.replace('$artistletter', (clean_context.get('artist', 'U') or 'U')[0].upper())
    result = result.replace('$artist', clean_context.get('artist', 'Unknown Artist'))
    result = result.replace('$album', clean_context.get('album', 'Unknown Album'))
    result = result.replace('$title', clean_context.get('title', 'Unknown Track'))
    # $cdnum must replace before $track to avoid conflict with variables that
    # start with "$c" — no such variable exists today but this ordering
    # mirrors the "longest first" rule used throughout this function.
    result = result.replace('$cdnum', cdnum_value)
    result = result.replace('$track', f"{clean_context.get('track_number', 1):02d}")
    result = result.replace('$year', str(clean_context.get('year', '')))  # Empty string instead of 'Unknown'

    # Clean up extra spaces that might result from empty variables
    import re
    result = re.sub(r'\s+', ' ', result)  # Multiple spaces to single space
    result = re.sub(r'\s*-\s*-\s*', ' - ', result)  # Clean up double dashes
    result = result.strip()  # Remove leading/trailing spaces

    return result

def _get_file_path_from_template(context: dict, template_type: str = 'album_path') -> tuple:
    """
    Build complete file path using configured templates.

    Args:
        context: Dict with all track/album metadata
        template_type: 'album_path', 'single_path', 'compilation_path', 'playlist_path'

    Returns:
        (folder_path, filename) tuple
    """
    # Check if template system is enabled
    if not config_manager.get('file_organization.enabled', True):
        # Fallback to hardcoded structure
        return None, None

    # Get template from config
    templates = config_manager.get('file_organization.templates', {})
    template = templates.get(template_type)

    if not template:
        # Fallback templates if config missing
        default_templates = {
            'album_path': '$albumartist/$albumartist - $album/$track - $title',
            'single_path': '$artist/$artist - $title/$title',
            'compilation_path': 'Compilations/$album/$track - $artist - $title',
            'playlist_path': '$playlist/$artist - $title'
        }
        template = default_templates.get(template_type, '$artist/$album/$track - $title')

    # Apply template
    full_path = _apply_path_template(template, context)

    # Split into folder and filename
    path_parts = full_path.split('/')

    # Handle $quality and $disc: only substituted in the filename (last component).
    # In folder components they become empty string to prevent album splits
    # when tracks arrive in mixed qualities or disc numbers in folder names.
    import re
    quality_value = context.get('quality', '')
    disc_value = f"{context.get('disc_number', 1):02d}"
    disc_value_raw = str(context.get('disc_number', 1))

    if len(path_parts) > 1:
        folder_parts = path_parts[:-1]
        filename_base = path_parts[-1]

        # Strip $quality, $discnum, $disc from folder parts and clean up artifacts
        # $discnum before $disc — longer match first to prevent partial replacement
        cleaned_folders = []
        for part in folder_parts:
            part = part.replace('$quality', '')
            part = part.replace('$discnum', '')
            part = part.replace('$disc', '')
            part = re.sub(r'\s*\[\s*\]', '', part)   # empty []
            part = re.sub(r'\s*\(\s*\)', '', part)   # empty ()
            part = re.sub(r'\s*\{\s*\}', '', part)   # empty {}
            part = re.sub(r'\s*-\s*$', '', part)     # trailing dash
            part = re.sub(r'^\s*-\s*', '', part)     # leading dash
            part = re.sub(r'\s+', ' ', part).strip()
            if part:
                cleaned_folders.append(part)

        # Substitute $quality, $discnum, $disc in filename only
        # $discnum before $disc — longer match first
        filename_base = filename_base.replace('$quality', quality_value)
        filename_base = filename_base.replace('$discnum', disc_value_raw)
        filename_base = filename_base.replace('$disc', disc_value)
        # Clean up empty brackets/parens from any variable that resolved to empty
        filename_base = re.sub(r'\s*\[\s*\]', '', filename_base)
        filename_base = re.sub(r'\s*\(\s*\)', '', filename_base)
        filename_base = re.sub(r'\s*\{\s*\}', '', filename_base)
        filename_base = re.sub(r'\s*-\s*$', '', filename_base)
        # Leading dash cleanup — lets $cdnum (and other optional vars) sit at
        # the start of the filename without leaving a stray "- " when empty.
        filename_base = re.sub(r'^\s*-\s*', '', filename_base)
        filename_base = re.sub(r'\s+', ' ', filename_base).strip()

        # Sanitize each folder component
        sanitized_folders = [_sanitize_filename(part) for part in cleaned_folders]
        folder_path = os.path.join(*sanitized_folders) if sanitized_folders else ''

        # Sanitize filename
        filename = _sanitize_filename(filename_base)

        return folder_path, filename
    else:
        # Single component, treat as filename — substitute $quality, $discnum, $disc
        full_path = full_path.replace('$quality', quality_value)
        full_path = full_path.replace('$discnum', disc_value_raw)
        full_path = full_path.replace('$disc', disc_value)
        full_path = re.sub(r'\s*\[\s*\]', '', full_path)
        full_path = re.sub(r'\s*\(\s*\)', '', full_path)
        full_path = re.sub(r'\s*\{\s*\}', '', full_path)
        full_path = re.sub(r'\s*-\s*$', '', full_path)
        full_path = re.sub(r'^\s*-\s*', '', full_path)
        full_path = re.sub(r'\s+', ' ', full_path).strip()
        return '', _sanitize_filename(full_path)

# METADATA & COVER ART HELPERS (Ported from downloads.py)
