@app.route('/api/hifi/status', methods=['GET'])
def hifi_status():
    """Check if HiFi API instances are reachable."""
    try:
        hifi = soulseek_client.hifi
        available = hifi.is_available()
        version = hifi.get_version() if available else None
        return jsonify({
            "available": available,
            "version": version,
            "instance": hifi._get_instance(),
        })
    except Exception as e:
        return jsonify({"available": False, "error": str(e)})


@app.route('/api/hifi/instances', methods=['GET'])
def hifi_instances():
    """Check availability of all HiFi API instances."""
    import requests as req
    try:
        hifi = soulseek_client.hifi
        instances = list(hifi._instances)
        results = []
        for url in instances:
            entry = {'url': url, 'status': 'unknown', 'version': None, 'can_search': False, 'can_download': False}
            try:
                # Check root for version
                r = req.get(f'{url}/', timeout=5, headers={'Accept': 'application/json'})
                if r.ok:
                    data = r.json()
                    entry['version'] = data.get('version')
                    entry['status'] = 'online'
                    # Check search
                    sr = req.get(f'{url}/search', params={'s': 'test', 'limit': 1}, timeout=5)
                    entry['can_search'] = sr.ok
                    # Check track (download capability)
                    tr = req.get(f'{url}/track', params={'id': '1550546', 'quality': 'LOSSLESS'}, timeout=5)
                    entry['can_download'] = tr.ok
                    if not tr.ok:
                        entry['download_error'] = f'HTTP {tr.status_code}'
                else:
                    entry['status'] = f'error (HTTP {r.status_code})'
            except req.exceptions.SSLError:
                entry['status'] = 'ssl_error'
            except req.exceptions.ConnectTimeout:
                entry['status'] = 'timeout'
            except req.exceptions.ConnectionError:
                entry['status'] = 'offline'
            except Exception as e:
                entry['status'] = f'error ({type(e).__name__})'
            results.append(entry)
        return jsonify({'instances': results, 'active': hifi._get_instance()})
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/hifi/instances', methods=['POST'])
@admin_only
def hifi_add_instance():
    """Add a new HiFi API instance."""
    try:
        data = request.get_json() or {}
        url = data.get('url', '').strip().rstrip('/')
        if not url:
            return jsonify({'success': False, 'error': 'URL is required'}), 400
        if not url.startswith(('http://', 'https://')):
            return jsonify({'success': False, 'error': 'URL must start with http:// or https://'}), 400
        from database.music_database import get_database
        db = get_database()
        # Get current count to assign next priority
        existing = db.get_all_hifi_instances()
        priority = len(existing)
        added = db.add_hifi_instance(url, priority)
        if not added:
            return jsonify({'success': False, 'error': 'Instance already exists'}), 400
        # Reload the client
        if soulseek_client and hasattr(soulseek_client, 'hifi') and soulseek_client.hifi:
            soulseek_client.hifi.reload_instances()
        return jsonify({'success': True, 'url': url})
    except Exception as e:
        logger.error(f"Error adding HiFi instance: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


