@app.route('/api/tidal/playlists', methods=['GET'])
def get_tidal_playlists():
    """Fetches all user playlists from Tidal with full track data (like sync.py)."""
    if not tidal_client or not tidal_client.is_authenticated():
        return jsonify({"error": "Tidal not authenticated."}), 401
    try:
        # Use same method as sync.py - this already includes all track data
        playlists = tidal_client.get_user_playlists_metadata_only()
        
        playlist_data = []
        for p in playlists:
            # Get track count from metadata (set during listing) or actual tracks
            track_count = getattr(p, 'track_count', 0) or (len(p.tracks) if hasattr(p, 'tracks') and p.tracks else 0)
            
            playlist_dict = {
                "id": p.id, 
                "name": p.name, 
                "owner": getattr(p, 'owner', 'Unknown'),
                "track_count": track_count,
                "image_url": getattr(p, 'image_url', None),
                "description": getattr(p, 'description', ''),
                "tracks": []  # Add tracks data like sync.py
            }
            
            # Include full track data if available (like sync.py has)
            if hasattr(p, 'tracks') and p.tracks:
                playlist_dict['tracks'] = [{
                    'id': t.id,
                    'name': t.name, 
                    'artists': t.artists or [],
                    'album': getattr(t, 'album', 'Unknown Album'),
                    'duration_ms': getattr(t, 'duration_ms', 0),
                    'track_number': getattr(t, 'track_number', 0)
                } for t in p.tracks]
                
            playlist_data.append(playlist_dict)
            
        logger.info(f"Loaded {len(playlist_data)} Tidal playlists with track data")
        return jsonify(playlist_data)
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/api/tidal/playlist/<playlist_id>', methods=['GET'])
def get_tidal_playlist_tracks(playlist_id):
    """Fetches full track details for a specific Tidal playlist (matches sync.py pattern)."""
    if not tidal_client or not tidal_client.is_authenticated():
        return jsonify({"error": "Tidal not authenticated."}), 401
    try:
        logger.info(f"Getting full Tidal playlist with tracks for: {playlist_id}")

        # Fetch this single playlist directly — no need to re-fetch all playlists
        full_playlist = tidal_client.get_playlist(playlist_id)
        if not full_playlist:
            return jsonify({"error": "Playlist not found or unable to access. This may be due to privacy settings or Tidal API restrictions."}), 404
            
        if not full_playlist.tracks:
            return jsonify({"error": "This playlist appears to have no tracks or they cannot be accessed"}), 403
        
        logger.info(f"Loaded {len(full_playlist.tracks)} tracks from Tidal playlist: {full_playlist.name}")
        
        # Convert playlist to dict (matches sync.py structure)
        playlist_dict = {
            'id': full_playlist.id,
            'name': full_playlist.name,
            'description': getattr(full_playlist, 'description', ''),
            'owner': getattr(full_playlist, 'owner', 'Unknown'),
            'track_count': len(full_playlist.tracks),
            'image_url': getattr(full_playlist, 'image_url', None),
            'tracks': []
        }
        
        # Convert tracks to dict format (for discovery modal)
        playlist_dict['tracks'] = [{
            'id': t.id,
            'name': t.name, 
            'artists': t.artists or [],
            'album': getattr(t, 'album', 'Unknown Album'),
            'duration_ms': getattr(t, 'duration_ms', 0),
            'track_number': getattr(t, 'track_number', 0)
        } for t in full_playlist.tracks]
        
        return jsonify(playlist_dict)
    except Exception as e:
        logger.error(f"Error getting Tidal playlist tracks: {e}")
        return jsonify({"error": str(e)}), 500


# ===================================================================
# TIDAL DISCOVERY API ENDPOINTS
# ===================================================================

# Global state for Tidal playlist discovery management
tidal_discovery_states = {}  # Key: playlist_id, Value: discovery state
tidal_discovery_executor = ThreadPoolExecutor(max_workers=3, thread_name_prefix="tidal_discovery")

@app.route('/api/tidal/discovery/start/<playlist_id>', methods=['POST'])
def start_tidal_discovery(playlist_id):
    """Start Spotify discovery process for a Tidal playlist"""
    try:
        # Get playlist data from Tidal
        if not tidal_client or not tidal_client.is_authenticated():
            return jsonify({"error": "Tidal not authenticated."}), 401

        # Fetch this single playlist directly — no need to re-fetch all playlists
        target_playlist = tidal_client.get_playlist(playlist_id)

        if not target_playlist:
            return jsonify({"error": "Tidal playlist not found"}), 404

        if not target_playlist.tracks:
            return jsonify({"error": "Playlist has no tracks"}), 400
        
        # Initialize discovery state if it doesn't exist, or update existing state
        if playlist_id in tidal_discovery_states:
            existing_state = tidal_discovery_states[playlist_id]
            if existing_state['phase'] == 'discovering':
                return jsonify({"error": "Discovery already in progress"}), 400
            # Update existing state for discovery
            existing_state['phase'] = 'discovering'
            existing_state['status'] = 'discovering' 
            existing_state['last_accessed'] = time.time()
            state = existing_state
        else:
            # Create new state for first-time discovery
            state = {
                'playlist': target_playlist,
                'phase': 'discovering', # fresh -> discovering -> discovered -> syncing -> sync_complete -> downloading -> download_complete
                'status': 'discovering',
                'discovery_progress': 0,
                'spotify_matches': 0,
                'spotify_total': len(target_playlist.tracks),
                'discovery_results': [],
                'sync_playlist_id': None,
                'converted_spotify_playlist_id': None,
                'download_process_id': None,  # Track associated download missing tracks process
                'created_at': time.time(),
                'last_accessed': time.time(),
                'discovery_future': None,
                'sync_progress': {}
            }
            tidal_discovery_states[playlist_id] = state
        
        # Add activity for discovery start
        add_activity_item("", "Tidal Discovery Started", f"'{target_playlist.name}' - {len(target_playlist.tracks)} tracks", "Now")
        
        # Start discovery worker (capture profile ID while we have Flask context)
        state['_profile_id'] = get_current_profile_id()
        future = tidal_discovery_executor.submit(_run_tidal_discovery_worker, playlist_id)
        state['discovery_future'] = future
        
        logger.info(f"Started Spotify discovery for Tidal playlist: {target_playlist.name}")
        return jsonify({"success": True, "message": "Discovery started"})
        
    except Exception as e:
        logger.error(f"Error starting Tidal discovery: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/tidal/discovery/status/<playlist_id>', methods=['GET'])
def get_tidal_discovery_status(playlist_id):
    """Get real-time discovery status for a Tidal playlist"""
    try:
        if playlist_id not in tidal_discovery_states:
            return jsonify({"error": "Tidal discovery not found"}), 404
        
        state = tidal_discovery_states[playlist_id]
        state['last_accessed'] = time.time()  # Update access time
        
        response = {
            'phase': state['phase'],
            'status': state['status'],
            'progress': state['discovery_progress'],
            'spotify_matches': state['spotify_matches'],
            'spotify_total': state['spotify_total'],
            'results': state['discovery_results'],
            'complete': state['phase'] == 'discovered'
        }
        
        return jsonify(response)

    except Exception as e:
        logger.error(f"Error getting Tidal discovery status: {e}")
        return jsonify({"error": str(e)}), 500


@app.route('/api/tidal/discovery/update_match', methods=['POST'])
def update_tidal_discovery_match():
    """Update a Tidal discovery result with manually selected Spotify track"""
    try:
        data = request.get_json()
        identifier = data.get('identifier')  # playlist_id
        track_index = data.get('track_index')
        spotify_track = data.get('spotify_track')

        if not identifier or track_index is None or not spotify_track:
            return jsonify({'error': 'Missing required fields'}), 400

        # Get the state
        state = tidal_discovery_states.get(identifier)

        if not state:
            return jsonify({'error': 'Discovery state not found'}), 404

        if track_index >= len(state['discovery_results']):
            return jsonify({'error': 'Invalid track index'}), 400

        # Update the result
        result = state['discovery_results'][track_index]
        old_status = result.get('status')

        # Update with user-selected track
        result['status'] = 'Found'
        result['status_class'] = 'found'
        result['spotify_track'] = spotify_track['name']
        result['spotify_artist'] = _join_artist_names(spotify_track['artists']) if isinstance(spotify_track['artists'], list) else _extract_artist_name(spotify_track['artists'])
        result['spotify_album'] = spotify_track['album']
        result['spotify_id'] = spotify_track['id']

        # Format duration (Tidal doesn't show duration in table, but store it anyway)
        duration_ms = spotify_track.get('duration_ms', 0)
        if duration_ms:
            minutes = duration_ms // 60000
            seconds = (duration_ms % 60000) // 1000
            result['duration'] = f"{minutes}:{seconds:02d}"
        else:
            result['duration'] = '0:00'

        # IMPORTANT: Also set spotify_data for sync/download compatibility.
        # Manual match from the fix modal — build a rich spotify_data (album
        # as dict with image info) matching the normal discovery shape, and
        # explicitly clear any prior wing-it flag since the user picked a
        # real metadata match.
        result['spotify_data'] = _build_fix_modal_spotify_data(spotify_track)
        result['wing_it_fallback'] = False

        result['manual_match'] = True  # Flag for tracking

        # Update match count if status changed from not found/error
        if old_status != 'found' and old_status != 'Found':
            state['spotify_matches'] = state.get('spotify_matches', 0) + 1

        logger.info(f"Manual match updated: tidal - {identifier} - track {track_index}")
        logger.info(f"   → {result['spotify_artist']} - {result['spotify_track']}")

        # Save manual fix to discovery cache so it appears in discovery pool
        try:
            original_track = result.get('tidal_track', {})
            original_name = original_track.get('name', spotify_track['name'])
            original_artist = ''
            original_artists = original_track.get('artists', [])
            if original_artists:
                original_artist = original_artists[0] if isinstance(original_artists[0], str) else original_artists[0].get('name', '')

            cache_key = _get_discovery_cache_key(original_name, original_artist)
            # Normalize artists to plain strings for cache consistency
            artists_list = spotify_track['artists']
            if isinstance(artists_list, list):
                artists_list = [a if isinstance(a, str) else a.get('name', '') for a in artists_list]
            # Preserve cover image info so the download pipeline can find
            # artwork when this cached match is used later. The fix modal
            # sends image_url at the top level; search results often return
            # album as a bare string, which previously dropped the artwork.
            image_url = spotify_track.get('image_url') or ''
            album_raw = spotify_track.get('album', '')
            if isinstance(album_raw, dict):
                album_obj = dict(album_raw)
                if image_url and not album_obj.get('image_url'):
                    album_obj['image_url'] = image_url
                if image_url and not album_obj.get('images'):
                    album_obj['images'] = [{'url': image_url}]
            else:
                album_obj = {'name': album_raw or ''}
                if image_url:
                    album_obj['image_url'] = image_url
                    album_obj['images'] = [{'url': image_url}]

            matched_data = {
                'id': spotify_track['id'],
                'name': spotify_track['name'],
                'artists': artists_list,
                'album': album_obj,
                'duration_ms': spotify_track.get('duration_ms', 0),
                'image_url': image_url,
                'source': 'spotify',
            }
            cache_db = get_database()
            cache_db.save_discovery_cache_match(
                cache_key[0], cache_key[1], _get_active_discovery_source(), 1.0, matched_data,
                original_name, original_artist
            )
            logger.info(f"Manual fix saved to discovery cache: {original_name} by {original_artist}")
        except Exception as cache_err:
            logger.error(f"Error saving manual fix to discovery cache: {cache_err}")

        return jsonify({'success': True, 'result': result})

    except Exception as e:
        logger.error(f"Error updating Tidal discovery match: {e}")
        return jsonify({'error': str(e)}), 500


@app.route('/api/tidal/playlists/states', methods=['GET'])
def get_tidal_playlist_states():
    """Get all stored Tidal playlist discovery states for frontend hydration (similar to YouTube playlists)"""
    try:
        states = []
        current_time = time.time()
        
        for playlist_id, state in tidal_discovery_states.items():
            # Update access time when requested
            state['last_accessed'] = current_time
            
            # Return essential data for card state recreation
            state_info = {
                'playlist_id': playlist_id,
                'phase': state['phase'],
                'status': state['status'],
                'discovery_progress': state['discovery_progress'],
                'spotify_matches': state['spotify_matches'],
                'spotify_total': state['spotify_total'],
                'discovery_results': state['discovery_results'],
                'converted_spotify_playlist_id': state.get('converted_spotify_playlist_id'),
                'download_process_id': state.get('download_process_id'),
                'last_accessed': state['last_accessed']
            }
            states.append(state_info)
        
        logger.info(f"Returning {len(states)} stored Tidal playlist states for hydration")
        return jsonify({"states": states})
        
    except Exception as e:
        logger.error(f"Error getting Tidal playlist states: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/tidal/state/<playlist_id>', methods=['GET'])
def get_tidal_playlist_state(playlist_id):
    """Get specific Tidal playlist state (detailed version matching YouTube's state endpoint)"""
    try:
        if playlist_id not in tidal_discovery_states:
            return jsonify({"error": "Tidal playlist not found"}), 404
        
        state = tidal_discovery_states[playlist_id]
        state['last_accessed'] = time.time()
        
        # Return full state information (including results for modal hydration)
        response = {
            'playlist_id': playlist_id,
            'playlist': state['playlist'].__dict__ if hasattr(state['playlist'], '__dict__') else state['playlist'],
            'phase': state['phase'],
            'status': state['status'],
            'discovery_progress': state['discovery_progress'],
            'spotify_matches': state['spotify_matches'],
            'spotify_total': state['spotify_total'],
            'discovery_results': state['discovery_results'],
            'sync_playlist_id': state.get('sync_playlist_id'),
            'converted_spotify_playlist_id': state.get('converted_spotify_playlist_id'),
            'download_process_id': state.get('download_process_id'),
            'sync_progress': state.get('sync_progress', {}),
            'last_accessed': state['last_accessed']
        }
        
        return jsonify(response)
        
    except Exception as e:
        logger.error(f"Error getting Tidal playlist state: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/tidal/reset/<playlist_id>', methods=['POST'])
def reset_tidal_playlist(playlist_id):
    """Reset Tidal playlist to fresh phase (clear discovery/sync data)"""
    try:
        if playlist_id not in tidal_discovery_states:
            return jsonify({"error": "Tidal playlist not found"}), 404
        
        state = tidal_discovery_states[playlist_id]
        
        # Stop any active discovery
        if 'discovery_future' in state and state['discovery_future']:
            state['discovery_future'].cancel()
        
        # Reset state to fresh (preserve original playlist data)
        state['phase'] = 'fresh'
        state['status'] = 'fresh'
        state['discovery_results'] = []
        state['discovery_progress'] = 0
        state['spotify_matches'] = 0
        state['sync_playlist_id'] = None
        state['converted_spotify_playlist_id'] = None
        state['download_process_id'] = None
        state['sync_progress'] = {}
        state['discovery_future'] = None
        state['last_accessed'] = time.time()
        
        logger.info(f"Reset Tidal playlist to fresh: {playlist_id}")
        return jsonify({"success": True, "message": "Playlist reset to fresh phase"})
        
    except Exception as e:
        logger.error(f"Error resetting Tidal playlist: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/tidal/delete/<playlist_id>', methods=['POST'])
def delete_tidal_playlist(playlist_id):
    """Delete Tidal playlist state completely"""
    try:
        if playlist_id not in tidal_discovery_states:
            return jsonify({"error": "Tidal playlist not found"}), 404
        
        state = tidal_discovery_states[playlist_id]
        
        # Stop any active discovery
        if 'discovery_future' in state and state['discovery_future']:
            state['discovery_future'].cancel()
        
        # Remove from state dictionary
        del tidal_discovery_states[playlist_id]
        
        logger.info(f"Deleted Tidal playlist state: {playlist_id}")
        return jsonify({"success": True, "message": "Playlist deleted"})
        
    except Exception as e:
        logger.error(f"Error deleting Tidal playlist: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/tidal/update_phase/<playlist_id>', methods=['POST'])
def update_tidal_playlist_phase(playlist_id):
    """Update Tidal playlist phase (used when modal closes to reset from download_complete to discovered)"""
    try:
        if playlist_id not in tidal_discovery_states:
            return jsonify({"error": "Tidal playlist not found"}), 404
        
        data = request.get_json()
        if not data or 'phase' not in data:
            return jsonify({"error": "Phase not provided"}), 400
        
        new_phase = data['phase']
        valid_phases = ['fresh', 'discovering', 'discovered', 'syncing', 'sync_complete', 'downloading', 'download_complete']
        
        if new_phase not in valid_phases:
            return jsonify({"error": f"Invalid phase. Must be one of: {', '.join(valid_phases)}"}), 400
        
        state = tidal_discovery_states[playlist_id]
        old_phase = state.get('phase', 'unknown')
        state['phase'] = new_phase
        state['last_accessed'] = time.time()
        
        logger.info(f"Updated Tidal playlist {playlist_id} phase: {old_phase} → {new_phase}")
        return jsonify({"success": True, "message": f"Phase updated to {new_phase}", "old_phase": old_phase, "new_phase": new_phase})
        
    except Exception as e:
        logger.error(f"Error updating Tidal playlist phase: {e}")
        return jsonify({"error": str(e)}), 500


_playlist_discovery_cancelled = set()  # Set of automation_ids that have been cancelled

def _pause_enrichment_workers(label='discovery'):
    """Pause enrichment workers during discovery to reduce API contention.
    Returns dict of {name: was_running} for resume."""
    was_running = {}
    workers = {
        'Spotify': spotify_enrichment_worker,
        'iTunes': itunes_enrichment_worker,
        'Tidal': tidal_enrichment_worker if 'tidal_enrichment_worker' in globals() else None,
        'Qobuz': qobuz_enrichment_worker if 'qobuz_enrichment_worker' in globals() else None,
    }
    for name, worker in workers.items():
        try:
            if worker and not worker.paused:
                worker.pause()
                was_running[name] = True
                logger.warning(f"Paused {name} enrichment worker during {label}")
        except Exception:
            pass
    return was_running


def _resume_enrichment_workers(was_running, label='discovery'):
    """Resume enrichment workers that were paused by _pause_enrichment_workers."""
    workers = {
        'Spotify': spotify_enrichment_worker,
        'iTunes': itunes_enrichment_worker,
        'Tidal': tidal_enrichment_worker if 'tidal_enrichment_worker' in globals() else None,
        'Qobuz': qobuz_enrichment_worker if 'qobuz_enrichment_worker' in globals() else None,
    }
    for name, worker in workers.items():
        try:
            if was_running.get(name) and worker:
                worker.resume()
                logger.info(f"Resumed {name} enrichment worker after {label}")
        except Exception:
            pass


def _sync_discovery_results_to_mirrored(source_type, source_playlist_id, discovery_results, discovery_source, profile_id=1):
    """Write discovery results back to the mirrored playlist's extra_data.
    Called after Tidal/Deezer/Beatport discovery completes.
    Matches by source_track_id first, then by track position (index)."""
    try:
        db = get_database()
        playlists = db.get_mirrored_playlists(profile_id=profile_id)
        mirrored_pl = None
        for pl in playlists:
            if pl.get('source') == source_type and str(pl.get('source_playlist_id')) == str(source_playlist_id):
                mirrored_pl = pl
                break

        if not mirrored_pl:
            logger.warning(f"[Discovery Sync] No mirrored playlist found for {source_type}:{source_playlist_id} (profile {profile_id})")
            return

        logger.info(f"[Discovery Sync] Found mirrored playlist '{mirrored_pl.get('name')}' (DB id={mirrored_pl['id']}) for {source_type}:{source_playlist_id}")
        mirrored_tracks = db.get_mirrored_playlist_tracks(mirrored_pl['id'])
        if not mirrored_tracks:
            return

        # Build lookup maps: source_track_id → db_id AND position → db_id
        source_id_to_db_id = {}
        position_to_db_id = {}
        for mt in mirrored_tracks:
            sid = mt.get('source_track_id', '')
            if sid:
                source_id_to_db_id[str(sid)] = mt['id']
            pos = mt.get('position')
            if pos is not None:
                position_to_db_id[pos] = mt['id']

        updated = 0
        for result in discovery_results:
            if result.get('status') not in ('found', 'Found', 'Wing It'):
                continue

            match_data = result.get('match_data') or result.get('spotify_data')
            if not match_data:
                continue

            confidence = result.get('confidence', 0.85)

            # Try to find the mirrored track DB ID
            db_track_id = None

            # Method 1: match by source track ID
            source_track = result.get('tidal_track') or result.get('source_track') or {}
            source_tid = str(source_track.get('id', '')) if source_track else ''
            if source_tid and source_tid in source_id_to_db_id:
                db_track_id = source_id_to_db_id[source_tid]

            # Method 2: match by position/index
            if not db_track_id:
                idx = result.get('index')
                if idx is not None and idx in position_to_db_id:
                    db_track_id = position_to_db_id[idx]

            if not db_track_id:
                continue

            extra_data = {
                'discovered': True,
                'provider': discovery_source,
                'confidence': confidence,
                'matched_data': match_data,
            }
            if result.get('wing_it_fallback'):
                extra_data['wing_it_fallback'] = True
                extra_data['provider'] = 'wing_it_fallback'
            db.update_mirrored_track_extra_data(db_track_id, extra_data)
            updated += 1

        if updated > 0:
            logger.info(f"Synced {updated} discovery results back to mirrored playlist '{mirrored_pl.get('name', '')}'")

    except Exception as e:
        import traceback
        logger.error(f"Failed to sync discovery results to mirrored playlist: {e}")
        traceback.print_exc()


# Mirrored-playlist discovery worker logic lives in core/discovery/playlist.py.
from core.discovery import playlist as _discovery_playlist


def _build_playlist_discovery_deps():
    """Build the PlaylistDiscoveryDeps bundle from web_server.py globals on each call."""
    return _discovery_playlist.PlaylistDiscoveryDeps(
        spotify_client=spotify_client,
        matching_engine=matching_engine,
        automation_engine=automation_engine,
        playlist_discovery_cancelled=_playlist_discovery_cancelled,
        pause_enrichment_workers=_pause_enrichment_workers,
        resume_enrichment_workers=_resume_enrichment_workers,
        get_active_discovery_source=_get_active_discovery_source,
        get_metadata_fallback_client=_get_metadata_fallback_client,
        get_metadata_fallback_source=_get_metadata_fallback_source,
        update_automation_progress=_update_automation_progress,
        get_database=get_database,
        get_discovery_cache_key=_get_discovery_cache_key,
        validate_discovery_cache_artist=_validate_discovery_cache_artist,
        discovery_score_candidates=_discovery_score_candidates,
        get_metadata_cache=get_metadata_cache,
        build_discovery_wing_it_stub=_build_discovery_wing_it_stub,
    )


def _run_playlist_discovery_worker(playlists, automation_id=None):
    return _discovery_playlist.run_playlist_discovery_worker(
        playlists, automation_id, _build_playlist_discovery_deps()
    )



def _extract_artist_name(artist):
    """Extract artist name string from either a string or dict ({"name": "..."}) format."""
    if isinstance(artist, dict):
        return artist.get('name', '')
    return artist or ''

def _extract_artist_names(artists):
    """Extract a list of artist name strings from a list that may contain dicts or strings."""
    return [_extract_artist_name(a) for a in (artists or [])]

def _join_artist_names(artists):
    """Join artist names from a list that may contain dicts or strings."""
    return ', '.join(_extract_artist_names(artists))

def _get_discovery_cache_key(title, artist):
    """Normalize title/artist for discovery cache lookup using matching_engine."""
    norm_title = matching_engine.clean_title(title)
    norm_artist = matching_engine.clean_artist(_extract_artist_name(artist))
    return (norm_title, norm_artist)


def _validate_discovery_cache_artist(source_artist, cached_match):
    """Check if a cached discovery match has a valid artist. Returns False if the
    cached result's artist doesn't match the source artist (stale/wrong cache entry)."""
    min_artist_similarity = 0.5
    source_artist_cleaned = matching_engine.clean_artist(source_artist)
    if not source_artist_cleaned:
        return True  # No source artist to validate against

    cached_artists = cached_match.get('artists', [])
    if not cached_artists:
        return True  # No cached artist to check

    best_sim = 0.0
    for cand_artist in cached_artists:
        if not cand_artist:
            continue
        # Handle both string artists and dict artists ({"name": "..."})
        if isinstance(cand_artist, dict):
            cand_artist = cand_artist.get('name', '')
            if not cand_artist:
                continue
        cand_normalized = matching_engine.normalize_string(cand_artist)
        if source_artist_cleaned in cand_normalized:
            return True
        cand_cleaned = matching_engine.clean_artist(cand_artist)
        sim = matching_engine.similarity_score(source_artist_cleaned, cand_cleaned)
        if sim > best_sim:
            best_sim = sim

    if best_sim < min_artist_similarity:
        logger.info(f"Cache artist mismatch: source='{source_artist}' vs cached='{cached_artists[0]}' (sim={best_sim:.2f}), re-searching")
        return False
    return True


def _discovery_score_candidates(source_title, source_artist, source_duration_ms, search_results):
    """Score search results against a source track using the matching engine.

    Both artist AND title must independently pass minimum similarity floors.
    This prevents weighted scoring from allowing a perfect artist to carry a
    garbage title (or vice versa). If either dimension doesn't match, the
    candidate is rejected — no match is better than a wrong match.

    Args:
        source_title: The source track title (already cleaned for YouTube, raw for others)
        source_artist: The source track primary artist
        source_duration_ms: The source track duration in ms (0 if unknown)
        search_results: List of Track objects (Spotify or iTunes) from search

    Returns:
        (best_match, best_confidence, best_index) or (None, 0.0, -1) if no results
    """
    best_match = None
    best_confidence = 0.0
    best_index = -1
    min_artist_similarity = 0.5
    min_title_similarity = 0.5

    source_artist_cleaned = matching_engine.clean_artist(source_artist)
    source_title_cleaned = matching_engine.clean_title(source_title)
    source_core_title = matching_engine.get_core_string(source_title)

    for idx, result in enumerate(search_results):
        try:
            result_artists = result.artists if hasattr(result, 'artists') and result.artists else []
            result_name = result.name if hasattr(result, 'name') else ''
            result_duration = result.duration_ms if hasattr(result, 'duration_ms') else 0

            # Artist floor — both must match, not just the weighted score
            best_artist_sim = 0.0
            for cand_artist in result_artists:
                if not cand_artist:
                    continue
                cand_cleaned = matching_engine.clean_artist(cand_artist)
                cand_normalized = matching_engine.normalize_string(cand_artist)
                if source_artist_cleaned and source_artist_cleaned in cand_normalized:
                    best_artist_sim = 1.0
                    break
                sim = matching_engine.similarity_score(source_artist_cleaned, cand_cleaned)
                if sim > best_artist_sim:
                    best_artist_sim = sim

            if best_artist_sim < min_artist_similarity:
                continue

            # Title floor — both must match, not just the weighted score
            cand_title_cleaned = matching_engine.clean_title(result_name)
            cand_core_title = matching_engine.get_core_string(result_name)

            # Core title exact match bypasses the floor (e.g., "edamame" == "edamame")
            title_passes = False
            if source_core_title and cand_core_title and source_core_title == cand_core_title:
                title_passes = True
            else:
                title_sim = matching_engine.similarity_score(source_title_cleaned, cand_title_cleaned)
                if title_sim >= min_title_similarity:
                    title_passes = True

            if not title_passes:
                continue

            # Both floors passed — now do full scoring
            confidence, match_type = matching_engine.score_track_match(
                source_title=source_title,
                source_artists=[source_artist],
                source_duration_ms=source_duration_ms,
                candidate_title=result_name,
                candidate_artists=result_artists,
                candidate_duration_ms=result_duration
            )

            if confidence > best_confidence:
                best_confidence = confidence
                best_match = result
                best_index = idx

        except Exception as e:
            logger.error(f"Error scoring candidate {idx}: {e}")
            continue

    return best_match, best_confidence, best_index


def _run_tidal_discovery_worker(playlist_id):
    """Background worker for Tidal discovery process (Spotify preferred, iTunes fallback)"""
    _ew_state = {}
    try:
        _ew_state = _pause_enrichment_workers('Tidal discovery')
        state = tidal_discovery_states[playlist_id]
        playlist = state['playlist']

        # Determine which provider to use — respect user's configured primary source
        discovery_source = _get_active_discovery_source()
        use_spotify = (discovery_source == 'spotify') and spotify_client and spotify_client.is_spotify_authenticated()

        # Initialize fallback client if needed
        itunes_client_instance = None
        if not use_spotify:
            itunes_client_instance = _get_metadata_fallback_client()

        logger.info(f"Starting Tidal discovery for: {playlist.name} (using {discovery_source.upper()})")

        # Store discovery source in state for frontend
        state['discovery_source'] = discovery_source

        successful_discoveries = 0

        for i, tidal_track in enumerate(playlist.tracks):
            if state.get('cancelled', False):
                break

            try:
                logger.info(f"[{i+1}/{len(playlist.tracks)}] Searching {discovery_source.upper()}: {tidal_track.name} by {', '.join(tidal_track.artists)}")

                # Check discovery cache first
                cache_key = _get_discovery_cache_key(tidal_track.name, tidal_track.artists[0] if tidal_track.artists else '')
                try:
                    cache_db = get_database()
                    cached_match = cache_db.get_discovery_cache_match(cache_key[0], cache_key[1], discovery_source)
                    if cached_match and _validate_discovery_cache_artist(tidal_track.artists[0] if tidal_track.artists else '', cached_match):
                        logger.debug(f"CACHE HIT [{i+1}/{len(playlist.tracks)}]: {tidal_track.name} by {', '.join(tidal_track.artists)}")
                        result = {
                            'tidal_track': {
                                'id': tidal_track.id,
                                'name': tidal_track.name,
                                'artists': tidal_track.artists or [],
                                'album': getattr(tidal_track, 'album', 'Unknown Album'),
                                'duration_ms': getattr(tidal_track, 'duration_ms', 0),
                            },
                            'spotify_data': cached_match,
                            'match_data': cached_match,
                            'status': 'found',
                            'discovery_source': discovery_source
                        }
                        successful_discoveries += 1
                        state['spotify_matches'] = successful_discoveries
                        state['discovery_results'].append(result)
                        state['discovery_progress'] = int(((i + 1) / len(playlist.tracks)) * 100)
                        continue
                except Exception as cache_err:
                    logger.error(f"Cache lookup error: {cache_err}")

                # Use the search function with appropriate provider
                track_result = _search_spotify_for_tidal_track(
                    tidal_track,
                    use_spotify=use_spotify,
                    itunes_client=itunes_client_instance
                )

                # Create result entry - use 'match_data' as generic key for both providers
                result = {
                    'tidal_track': {
                        'id': tidal_track.id,
                        'name': tidal_track.name,
                        'artists': tidal_track.artists or [],
                        'album': getattr(tidal_track, 'album', 'Unknown Album'),
                        'duration_ms': getattr(tidal_track, 'duration_ms', 0),
                    },
                    'spotify_data': None,  # Keep for backwards compatibility
                    'match_data': None,    # Generic field for any provider
                    'status': 'not_found',
                    'discovery_source': discovery_source
                }

                match_confidence = 0.0

                if use_spotify and isinstance(track_result, tuple):
                    # Spotify: Function returns (Track, raw_data, confidence)
                    track_obj, raw_track_data, match_confidence = track_result
                    album_obj = raw_track_data.get('album', {}) if raw_track_data else {}
                    # Ensure album has a name — fall back to track_obj.album if raw_data was missing
                    if isinstance(album_obj, dict) and not album_obj.get('name') and track_obj.album:
                        album_obj['name'] = track_obj.album
                    elif not album_obj and track_obj.album:
                        album_obj = {'name': track_obj.album}
                    # Ensure release_date is present (raw Spotify data has it, but fallback may not)
                    if isinstance(album_obj, dict) and not album_obj.get('release_date'):
                        album_obj['release_date'] = getattr(track_obj, 'release_date', '') or ''
                    # Extract image URL from album data or track object
                    _album_images = album_obj.get('images', []) if isinstance(album_obj, dict) else []
                    _image_url = _album_images[0].get('url', '') if _album_images else (getattr(track_obj, 'image_url', '') or '')

                    match_data = {
                        'id': track_obj.id,
                        'name': track_obj.name,
                        'artists': track_obj.artists,
                        'album': album_obj,
                        'duration_ms': track_obj.duration_ms,
                        'external_urls': track_obj.external_urls,
                        'image_url': _image_url,
                        'source': 'spotify'
                    }
                    # Preserve track_number/disc_number from raw Spotify API data
                    if raw_track_data and raw_track_data.get('track_number'):
                        match_data['track_number'] = raw_track_data['track_number']
                    if raw_track_data and raw_track_data.get('disc_number'):
                        match_data['disc_number'] = raw_track_data['disc_number']
                    result['spotify_data'] = match_data
                    result['match_data'] = match_data
                    result['status'] = 'found'
                    result['confidence'] = match_confidence
                    successful_discoveries += 1
                    state['spotify_matches'] = successful_discoveries

                elif not use_spotify and track_result and isinstance(track_result, dict):
                    # Fallback: Function returns a dict with track data (includes 'confidence' key)
                    match_confidence = track_result.pop('confidence', 0.80)
                    match_data = track_result
                    match_data['source'] = discovery_source
                    # Extract image URL from album images
                    _fb_album = match_data.get('album', {})
                    _fb_images = _fb_album.get('images', []) if isinstance(_fb_album, dict) else []
                    if _fb_images and 'image_url' not in match_data:
                        match_data['image_url'] = _fb_images[0].get('url', '')
                    result['spotify_data'] = match_data
                    result['match_data'] = match_data
                    result['status'] = 'found'
                    result['confidence'] = match_confidence
                    successful_discoveries += 1
                    state['spotify_matches'] = successful_discoveries

                # Save to discovery cache if match found
                if result['status'] == 'found' and result.get('match_data'):
                    try:
                        cache_db = get_database()
                        cache_db.save_discovery_cache_match(
                            cache_key[0], cache_key[1], discovery_source, match_confidence,
                            result['match_data'], tidal_track.name,
                            tidal_track.artists[0] if tidal_track.artists else ''
                        )
                        logger.info(f"CACHE SAVED: {tidal_track.name} (confidence: {match_confidence:.3f})")
                    except Exception as cache_err:
                        logger.error(f"Cache save error: {cache_err}")

                # Auto Wing It fallback for unmatched tracks
                if result['status'] != 'found':
                    tidal_t = result.get('tidal_track', {})
                    stub = _build_discovery_wing_it_stub(
                        tidal_t.get('name', ''),
                        ', '.join(tidal_t.get('artists', [])),
                        tidal_t.get('duration_ms', 0)
                    )
                    result['status'] = 'found'
                    result['status_class'] = 'wing-it'
                    result['spotify_data'] = stub
                    result['match_data'] = stub
                    result['wing_it_fallback'] = True
                    result['confidence'] = 0
                    successful_discoveries += 1
                    state['spotify_matches'] = successful_discoveries
                    state['wing_it_count'] = state.get('wing_it_count', 0) + 1

                state['discovery_results'].append(result)
                state['discovery_progress'] = int(((i + 1) / len(playlist.tracks)) * 100)

                # Add delay between requests
                time.sleep(0.1)

            except Exception as e:
                logger.error(f"Error processing track {i+1}: {e}")
                # Add error result
                result = {
                    'tidal_track': {
                        'name': tidal_track.name,
                        'artists': tidal_track.artists or [],
                    },
                    'spotify_data': None,
                    'match_data': None,
                    'status': 'error',
                    'error': str(e),
                    'discovery_source': discovery_source
                }
                state['discovery_results'].append(result)
                state['discovery_progress'] = int(((i + 1) / len(playlist.tracks)) * 100)

        # Mark as complete
        state['phase'] = 'discovered'
        state['status'] = 'discovered'
        state['discovery_progress'] = 100

        # Add activity for discovery completion
        source_label = discovery_source.upper()
        add_activity_item("", f"Tidal Discovery Complete ({source_label})", f"'{playlist.name}' - {successful_discoveries}/{len(playlist.tracks)} tracks found", "Now")

        logger.info(f"Tidal discovery complete ({source_label}): {successful_discoveries}/{len(playlist.tracks)} tracks found")

        # Sync discovery results back to mirrored playlist
        _sync_discovery_results_to_mirrored('tidal', playlist_id, state.get('discovery_results', []), discovery_source, profile_id=state.get('_profile_id', 1))

    except Exception as e:
        logger.error(f"Error in Tidal discovery worker: {e}")
        state['phase'] = 'error'
        state['status'] = f'error: {str(e)}'
    finally:
        _resume_enrichment_workers(_ew_state, 'Tidal discovery')


def _search_spotify_for_tidal_track(tidal_track, use_spotify=True, itunes_client=None):
    """Search Spotify/fallback for a Tidal track using matching_engine for better accuracy

    Args:
        tidal_track: The Tidal track to search for
        use_spotify: If True, use Spotify; if False, use fallback source
        itunes_client: Fallback client instance (required when use_spotify=False)

    Returns:
        For Spotify: (Track, raw_data, confidence) tuple or None
        For fallback: dict with track data (includes 'confidence' key) or None
    """
    if use_spotify:
        if not spotify_client or not spotify_client.is_authenticated():
            return None
    else:
        if not itunes_client:
            return None

    try:
        # Get track info
        track_name = tidal_track.name
        artists = tidal_track.artists or []

        if not artists:
            return None

        artist_name = artists[0]  # Use primary artist
        source_duration = getattr(tidal_track, 'duration_ms', 0) or 0
        source_name = "Spotify" if use_spotify else _get_metadata_fallback_source().capitalize()

        logger.info(f"Tidal track: '{artist_name}' - '{track_name}' (searching {source_name})")

        # Use matching engine to generate search queries (with fallback)
        try:
            temp_track = type('TempTrack', (), {
                'name': track_name,
                'artists': [artist_name],
                'album': None
            })()
            search_queries = matching_engine.generate_download_queries(temp_track)
            logger.info(f"Generated {len(search_queries)} search queries for Tidal track")
        except Exception as e:
            logger.error(f"Matching engine failed for Tidal, falling back to basic queries: {e}")
            if use_spotify:
                search_queries = [
                    f'track:"{track_name}" artist:"{artist_name}"',
                    f'"{track_name}" "{artist_name}"',
                    f'{track_name} {artist_name}'
                ]
            else:
                search_queries = [
                    f'{artist_name} {track_name}',
                    f'{track_name} {artist_name}',
                    track_name
                ]

        best_match = None
        best_match_raw = None
        best_confidence = 0.0
        min_confidence = 0.9

        for query_idx, search_query in enumerate(search_queries):
            try:
                logger.debug(f"Tidal query {query_idx + 1}/{len(search_queries)}: {search_query} ({source_name})")

                if use_spotify and not _spotify_rate_limited():
                    results = spotify_client.search_tracks(search_query, limit=10)
                    if not results:
                        continue
                else:
                    results = itunes_client.search_tracks(search_query, limit=10)
                    if not results:
                        continue

                # Score all results using the matching engine
                match, confidence, match_idx = _discovery_score_candidates(
                    track_name, artist_name, source_duration, results
                )

                if match and confidence > best_confidence and confidence >= min_confidence:
                    best_confidence = confidence
                    best_match = match
                    if use_spotify and match.id:
                        _cache = get_metadata_cache()
                        best_match_raw = _cache.get_entity('spotify', 'track', match.id)
                    else:
                        best_match_raw = None
                    logger.info(f"New best Tidal match: {match.artists[0]} - {match.name} (confidence: {confidence:.3f})")

                if best_confidence >= 0.9:
                    logger.info(f"High confidence Tidal match found ({best_confidence:.3f}), stopping search")
                    break

            except Exception as e:
                logger.debug(f"Error in Tidal {source_name} search for query '{search_query}': {e}")
                continue

        # Strategy 4: Extended search with higher limit (last resort)
        if not best_match:
            logger.info("Tidal Strategy 4: Extended search with limit=50")
            query = f"{artist_name} {track_name}"
            if use_spotify:
                extended_results = spotify_client.search_tracks(query, limit=50)
            else:
                extended_results = itunes_client.search_tracks(query, limit=50)
            if extended_results:
                match, confidence, match_idx = _discovery_score_candidates(
                    track_name, artist_name, source_duration, extended_results
                )
                if match and confidence >= min_confidence:
                    best_match = match
                    best_confidence = confidence
                    logger.info(f"Strategy 4 Tidal match (extended): {match.artists[0]} - {match.name} (confidence: {confidence:.3f})")

        if best_match:
            if use_spotify:
                logger.info(f"Final Tidal Spotify match: {best_match.artists[0]} - {best_match.name} (confidence: {best_confidence:.3f})")
                return (best_match, best_match_raw, best_confidence)
            else:
                result_artists = best_match.artists if hasattr(best_match, 'artists') else []
                result_artist = result_artists[0] if result_artists else 'Unknown'
                result_name = best_match.name if hasattr(best_match, 'name') else 'Unknown'
                logger.info(f"Final Tidal {source_name} match: {result_artist} - {result_name} (confidence: {best_confidence:.3f})")

                album_name = best_match.album if hasattr(best_match, 'album') else 'Unknown Album'
                image_url = best_match.image_url if hasattr(best_match, 'image_url') else ''
                track_id = best_match.id if hasattr(best_match, 'id') else ''
                duration_ms = best_match.duration_ms if hasattr(best_match, 'duration_ms') else 0

                # Fetch full track details to get album ID, track_number, etc.
                # The Track dataclass strips this data — the API has it
                album_obj = {
                    'name': album_name,
                    'album_type': 'album',
                    'release_date': getattr(best_match, 'release_date', '') or '',
                    'images': [{'url': image_url, 'height': 300, 'width': 300}] if image_url else []
                }
                track_number = None
                disc_number = None
                if track_id:
                    try:
                        detailed = itunes_client.get_track_details(track_id)
                        if detailed and isinstance(detailed.get('album'), dict):
                            dt_album = detailed['album']
                            if dt_album.get('id'):
                                album_obj['id'] = dt_album['id']
                            if dt_album.get('total_tracks'):
                                album_obj['total_tracks'] = dt_album['total_tracks']
                            if dt_album.get('release_date') and not album_obj.get('release_date'):
                                album_obj['release_date'] = dt_album['release_date']
                            if dt_album.get('album_type'):
                                album_obj['album_type'] = dt_album['album_type']
                            if dt_album.get('images') and not album_obj.get('images'):
                                album_obj['images'] = dt_album['images']
                            if dt_album.get('artists'):
                                album_obj['artists'] = dt_album['artists']
                        if detailed:
                            track_number = detailed.get('track_number')
                            disc_number = detailed.get('disc_number')
                            logger.info(f"[Discovery Enrich] {result_name}: track_number={track_number}, disc={disc_number}")
                        else:
                            logger.info(f"[Discovery Enrich] get_track_details returned None for ID {track_id} ({result_name})")
                    except Exception as _enrich_err:
                        logger.error(f"[Discovery Enrich] Failed for {result_name} (ID {track_id}): {_enrich_err}")

                result_data = {
                    'id': track_id,
                    'name': result_name,
                    'artists': [result_artist],
                    'album': album_obj,
                    'duration_ms': duration_ms,
                    'source': _get_metadata_fallback_source(),
                    'confidence': best_confidence
                }
                if track_number:
                    result_data['track_number'] = track_number
                if disc_number:
                    result_data['disc_number'] = disc_number
                return result_data
        else:
            logger.warning(f"No suitable Tidal match found (best confidence was {best_confidence:.3f}, required {min_confidence:.3f})")
            return None

    except Exception as e:
        logger.error(f"Error searching Spotify for Tidal track: {e}")
        return None


def convert_tidal_results_to_spotify_tracks(discovery_results):
    """Convert Tidal discovery results to Spotify tracks format for sync"""
    spotify_tracks = []

    for result in discovery_results:
        # Support both data formats: spotify_data (manual fixes) and individual fields (automatic discovery)
        if result.get('spotify_data'):
            spotify_data = result['spotify_data']

            # Create track object matching the expected format
            track = {
                'id': spotify_data['id'],
                'name': spotify_data['name'],
                'artists': spotify_data['artists'],
                'album': spotify_data['album'],
                'duration_ms': spotify_data.get('duration_ms', 0)
            }
            if spotify_data.get('track_number'):
                track['track_number'] = spotify_data['track_number']
            if spotify_data.get('disc_number'):
                track['disc_number'] = spotify_data['disc_number']
            spotify_tracks.append(track)
        elif result.get('spotify_track') and result.get('status_class') == 'found':
            # Build from individual fields (automatic discovery format)
            track = {
                'id': result.get('spotify_id', 'unknown'),
                'name': result.get('spotify_track', 'Unknown Track'),
                'artists': [result.get('spotify_artist', 'Unknown Artist')] if result.get('spotify_artist') else ['Unknown Artist'],
                'album': result.get('spotify_album', 'Unknown Album'),
                'duration_ms': 0
            }
            spotify_tracks.append(track)

    logger.info(f"Converted {len(spotify_tracks)} Tidal matches to Spotify tracks for sync")
    return spotify_tracks


