def _has_active_downloads():
    """Check if any download batches are currently active."""
    try:
        with tasks_lock:
            for batch_data in download_batches.values():
                if batch_data.get('phase') not in ('complete', 'error', 'cancelled', None):
                    return True
    except Exception:
        pass
    return False


# Track whether we auto-paused workers so we only resume ones we paused (not user-paused ones)
_download_auto_paused = set()
_download_yield_override = set()  # Workers the user explicitly resumed during downloads — don't re-pause


def _emit_rate_monitor_loop():
    """Background thread that pushes API call rate data every 1 second for speedometer gauges.
    Also includes enrichment worker status so the combined cards have everything."""
    # Map rate monitor service keys to enrichment status keys
    _enrichment_key_map = {
        'spotify': 'spotify_enrichment', 'itunes': 'itunes_enrichment',
        'deezer': 'deezer_enrichment', 'lastfm': 'lastfm', 'genius': 'genius',
        'musicbrainz': 'musicbrainz', 'audiodb': 'audiodb', 'discogs': 'discogs',
        'tidal': 'tidal_enrichment', 'qobuz': 'qobuz_enrichment',
    }

    while not globals().get('IS_SHUTTING_DOWN', False):
        socketio.sleep(1)
        try:
            from core.api_call_tracker import api_call_tracker
            payload = api_call_tracker.get_all_rates()

            # Merge enrichment worker status into each service
            try:
                enrichment = _get_enrichment_status()
                for svc_key, entry in payload.items():
                    enr_key = _enrichment_key_map.get(svc_key)
                    enr = enrichment.get(enr_key) if enr_key else None
                    if enr:
                        entry['worker'] = {
                            'status': 'not_configured' if not enr.get('configured') else
                                      'paused' if enr.get('paused') else
                                      'idle' if enr.get('idle') else
                                      'running' if enr.get('running') else 'stopped',
                            'yield_reason': enr.get('yield_reason', ''),
                            'calls_1h': enr.get('calls_1h', 0),
                            'calls_24h': enr.get('calls_24h', 0),
                        }
                        if svc_key == 'spotify' and enr.get('daily_budget'):
                            entry['worker']['daily_budget'] = enr['daily_budget']
            except Exception:
                pass

            # Add Spotify rate limit state
            try:
                if spotify_client:
                    rl_info = spotify_client.get_rate_limit_info()
                    if rl_info:
                        payload['spotify']['rate_limited'] = True
                        payload['spotify']['rl_remaining'] = rl_info.get('remaining_seconds', 0)
                        payload['spotify']['rl_endpoint'] = rl_info.get('endpoint', '')
            except Exception:
                pass

            socketio.emit('rate-monitor:update', payload)
        except Exception as e:
            logger.debug(f"Error emitting rate monitor: {e}")


def _emit_enrichment_status_loop():
    """Background thread that pushes all enrichment worker statuses every 2 seconds.
    Also auto-pauses rate-limited enrichment workers during active downloads."""
    workers = {
        'musicbrainz': lambda: mb_worker,
        'audiodb': lambda: audiodb_worker,
        'discogs': lambda: discogs_worker,
        'deezer': lambda: deezer_worker,
        'spotify-enrichment': lambda: spotify_enrichment_worker,
        'itunes-enrichment': lambda: itunes_enrichment_worker,
        'lastfm-enrichment': lambda: lastfm_worker,
        'genius-enrichment': lambda: genius_worker,
        'tidal-enrichment': lambda: tidal_enrichment_worker,
        'qobuz-enrichment': lambda: qobuz_enrichment_worker,
        'hydrabase': lambda: hydrabase_worker,
        'soulid': lambda: soulid_worker,
        'listening-stats': lambda: listening_stats_worker,
        'repair': lambda: repair_worker,
    }

    # Workers to auto-pause during downloads (rate-limit sensitive services)
    yield_workers = {
        'spotify-enrichment': lambda: spotify_enrichment_worker,
        'lastfm-enrichment': lambda: lastfm_worker,
        'genius-enrichment': lambda: genius_worker,
    }

    while not globals().get('IS_SHUTTING_DOWN', False):
        socketio.sleep(2)

        # Auto-pause/resume rate-limited workers during downloads
        try:
            downloading = _has_active_downloads()
            if not downloading:
                _download_yield_override.clear()  # Reset overrides when downloads finish
            for name, get_w in yield_workers.items():
                w = get_w()
                if w is None:
                    continue
                if downloading and not w.paused and name not in _download_yield_override:
                    w.paused = True
                    _download_auto_paused.add(name)
                    logger.debug(f"Auto-paused {name} during active downloads")
                elif not downloading and name in _download_auto_paused:
                    # Don't override an explicit user pause. If config says the worker
                    # was paused via the UI, leave it paused and just drop the auto-pause
                    # marker so the next auto-pause/resume cycle behaves normally.
                    config_key = f"{name.replace('-', '_')}_paused"
                    user_paused = config_manager.get(config_key, False)
                    _download_auto_paused.discard(name)
                    if not user_paused:
                        w.paused = False
                        logger.debug(f"Auto-resumed {name} after downloads finished")
                    else:
                        logger.debug(f"Downloads finished but {name} remains paused by user")
        except Exception as e:
            logger.debug(f"Error in download-yield check: {e}")

        for name, get_worker in workers.items():
            try:
                worker = get_worker()
                if worker is None:
                    continue
                status = worker.get_stats()
                # Flag workers that were auto-paused for downloads
                if name in _download_auto_paused:
                    status['yield_reason'] = 'downloads'
                socketio.emit(f'enrichment:{name}', status)
            except Exception as e:
                logger.debug(f"Error emitting {name} status: {e}")

def _emit_tool_progress_loop():
    """Background thread that pushes all tool progress statuses every 1 second."""
    while not globals().get('IS_SHUTTING_DOWN', False):
        socketio.sleep(1)
        # Stream status
        try:
            with stream_lock:
                socketio.emit('tool:stream', {
                    "status": stream_state["status"],
                    "progress": stream_state["progress"],
                    "track_info": stream_state["track_info"],
                    "error_message": stream_state["error_message"]
                })
        except Exception as e:
            logger.debug(f"Error emitting stream status: {e}")
        # Quality Scanner
        try:
            with quality_scanner_lock:
                socketio.emit('tool:quality-scanner', dict(quality_scanner_state))
        except Exception as e:
            logger.debug(f"Error emitting quality scanner status: {e}")
        # Duplicate Cleaner (add computed space_freed_mb)
        try:
            with duplicate_cleaner_lock:
                state_copy = duplicate_cleaner_state.copy()
                state_copy["space_freed_mb"] = duplicate_cleaner_state["space_freed"] / (1024 * 1024)
                socketio.emit('tool:duplicate-cleaner', state_copy)
        except Exception as e:
            logger.debug(f"Error emitting duplicate cleaner status: {e}")
        # Retag
        try:
            with retag_lock:
                socketio.emit('tool:retag', dict(retag_state))
        except Exception as e:
            logger.debug(f"Error emitting retag status: {e}")
        # DB Update
        try:
            with db_update_lock:
                socketio.emit('tool:db-update', dict(db_update_state))
        except Exception as e:
            logger.debug(f"Error emitting db update status: {e}")
        # Metadata Update (match HTTP wrapper: {success, status})
        try:
            state_copy = metadata_update_state.copy()
            if state_copy.get('started_at'):
                state_copy['started_at'] = state_copy['started_at'].isoformat()
            if state_copy.get('completed_at'):
                state_copy['completed_at'] = state_copy['completed_at'].isoformat()
            socketio.emit('tool:metadata', {"success": True, "status": state_copy})
        except Exception as e:
            logger.debug(f"Error emitting metadata status: {e}")
        # Logs (format activity_feed same as HTTP endpoint)
        try:
            with activity_feed_lock:
                recent = activity_feed[-50:][::-1]
                formatted = []
                for a in recent:
                    ts = a.get('time', 'Unknown')
                    icon = a.get('icon', '•')
                    title = a.get('title', 'Activity')
                    sub = a.get('subtitle', '')
                    formatted.append(f"[{ts}] {icon} {title} - {sub}" if sub else f"[{ts}] {icon} {title}")
                if not formatted:
                    formatted = ["No recent activity.", "Sync and download operations..."]
                socketio.emit('tool:logs', {'logs': formatted})
        except Exception as e:
            logger.debug(f"Error emitting logs: {e}")

def _emit_live_log_loop():
    """Background thread that tails app.log and pushes new lines via WebSocket."""
    _last_pos = {}  # {source: file_position}
    _active_source = 'app'
    log_map = {
        'app': Path(_log_path),
        'acoustid': _log_dir / 'acoustid.log',
        'post_processing': _log_dir / 'post_processing.log',
        'source_reuse': _log_dir / 'source_reuse.log',
    }
    while not globals().get('IS_SHUTTING_DOWN', False):
        socketio.sleep(0.5)
        try:
            # Read which source clients want (stored by subscribe handler)
            source = getattr(_emit_live_log_loop, '_source', 'app')
            log_path = log_map.get(source, log_map['app'])
            if not os.path.exists(log_path):
                continue

            file_size = os.path.getsize(log_path)
            last_pos = _last_pos.get(source, 0)

            # File was truncated or rotated
            if file_size < last_pos:
                last_pos = 0

            if file_size == last_pos:
                continue  # No new data

            new_lines = []
            with open(log_path, 'r', encoding='utf-8', errors='replace') as f:
                f.seek(last_pos)
                for line in f:
                    stripped = line.rstrip()
                    if stripped:
                        new_lines.append(stripped)
                _last_pos[source] = f.tell()

            if new_lines:
                # Cap at 50 lines per push to avoid flooding
                socketio.emit('logs:live', {
                    'lines': new_lines[-50:],
                    'source': source,
                })
        except Exception as e:
            logger.debug(f"Error in live log emitter: {e}")

_emit_live_log_loop._source = 'app'


@socketio.on('logs:subscribe')
def handle_logs_subscribe(data):
    """Client subscribes to live log stream with optional source."""
    source = data.get('source', 'app')
    _emit_live_log_loop._source = source
    join_room('logs:live')


